            var rois = new Dictionary<string, List<CRectangleObject>>
            {
                ["OK"] = new List<CRectangleObject>
                {
                    new CRectangleObject { Roi = new Rectangle(25, 25, 50, 50), cClassItem = data.ClassNamedList[0] }
                }
            };

            using (Bitmap image = new Bitmap(100, 100))
            {
                YoloAnnotationService.SaveAnnotations("sample.png", image, rois, data.ClassNamedList, data);
            }

            string trainLabel = Path.Combine(root, "data", "train", "labels", "sample.txt");
            string validLabel = Path.Combine(root, "data", "valid", "labels", "sample.txt");
            string trainImage = Path.Combine(root, "data", "train", "images", "sample.jpeg");
            AssertTrue(File.Exists(trainLabel), "train label file was not created");
            AssertTrue(!File.Exists(validLabel), "valid label file should not be created when validation split is 0%");
            AssertTrue(File.Exists(trainImage), "train image file was not created");
            AssertEqual("0 0.5 0.5 0.5 0.5", File.ReadAllText(trainLabel).Trim());

            rois["OK"][0].Roi = new Rectangle(10, 20, 30, 40);
            DateTime imageStampBefore = File.GetLastWriteTimeUtc(trainImage).AddMinutes(-5);
            File.SetLastWriteTimeUtc(trainImage, imageStampBefore);
            imageStampBefore = File.GetLastWriteTimeUtc(trainImage);
            using (Bitmap image = new Bitmap(100, 100))
            {
                YoloAnnotationService.SaveAnnotations("sample.png", image, rois, data.ClassNamedList, data);
            }

            AssertEqual(imageStampBefore, File.GetLastWriteTimeUtc(trainImage));
            AssertEqual("0 0.25 0.4 0.3 0.4", File.ReadAllText(trainLabel).Trim());

            IReadOnlyDictionary<string, List<Rectangle>> loaded = YoloAnnotationService.LoadAnnotationRectanglesForImage(
                trainImage,
                data.ClassNamedList,
                data,
                new Size(100, 100));

            AssertEqual(new Rectangle(10, 20, 30, 40), loaded["OK"][0]);
        }
        finally
        {
            DeleteTempRoot(root);
        }
    }

    private static void TestYoloAnnotationPreservesSourceImageExtensionAndSplitOwnership()
    {
        string root = CreateTempRoot();
        try
        {
            var data = new CData();
            data.ConfigureOutputRoot(root);
            data.ProjectSettings.YoloDataset.ValidationPercent = 0;
            data.ProjectSettings.YoloDataset.TestPercent = 0;
            data.ClassNamedList.Add(new CClassItem { Text = "Defect", DrawColor = Color.Red });
            data.EnsureYoloOutputDirectories();

            string fileStem = "split-sample";
            string trainJpg = Path.Combine(root, "data", "train", "images", $"{fileStem}.jpg");
            string trainJpeg = Path.Combine(root, "data", "train", "images", $"{fileStem}.jpeg");
            string trainLabel = Path.Combine(root, "data", "train", "labels", $"{fileStem}.txt");
            string validJpg = Path.Combine(root, "data", "valid", "images", $"{fileStem}.jpg");
            string validJpeg = Path.Combine(root, "data", "valid", "images", $"{fileStem}.jpeg");
            string validLabel = Path.Combine(root, "data", "valid", "labels", $"{fileStem}.txt");

            using (Bitmap source = CreateSolidBitmap(80, 60, Color.Black))
            {
                source.Save(trainJpg, System.Drawing.Imaging.ImageFormat.Jpeg);
            }

            File.WriteAllText(trainJpeg, "stale duplicate");
            data.LastSelectImageName = fileStem;
            data.LastSelectImagePath = trainJpg;

            var rois = new Dictionary<string, List<CRectangleObject>>
            {
                ["Defect"] = new List<CRectangleObject>
                {
                    new CRectangleObject { Roi = new Rectangle(10, 12, 20, 18), cClassItem = data.ClassNamedList[0] }
                }
            };

            using (Bitmap image = CreateSolidBitmap(80, 60, Color.Black))
            {
                YoloAnnotationService.SaveAnnotations($"{fileStem}.png", image, rois, data.ClassNamedList, data);
            }

            AssertTrue(File.Exists(trainJpg), "source .jpg image should remain the train artifact");
            AssertTrue(!File.Exists(trainJpeg), "stale .jpeg sibling should be removed after source-extension save");
            AssertTrue(File.Exists(trainLabel), "train label should exist after train-target save");
            AssertTrue(!File.Exists(validJpg), "valid image should not exist before the split changes");
            AssertTrue(!File.Exists(validLabel), "valid label should not exist before the split changes");

            data.ProjectSettings.YoloDataset.ValidationPercent = 100;
            data.LastSelectImagePath = trainJpg;
            using (Bitmap image = CreateSolidBitmap(80, 60, Color.White))
            {
                YoloAnnotationService.SaveAnnotations($"{fileStem}.png", image, rois, data.ClassNamedList, data);
            }

            AssertTrue(!File.Exists(trainJpg), "same-stem train image should be removed when the split target changes to valid");
            AssertTrue(!File.Exists(trainJpeg), "same-stem stale train image should stay removed when the split target changes");
            AssertTrue(!File.Exists(trainLabel), "same-stem train label should be removed when the split target changes to valid");
            AssertTrue(File.Exists(validJpg), "valid image should preserve the loaded source .jpg extension");
            AssertTrue(!File.Exists(validJpeg), "valid split should not create an extra .jpeg copy for a .jpg source");
            AssertTrue(File.Exists(validLabel), "valid label should exist after valid-target save");
        }
        finally
        {
            DeleteTempRoot(root);
        }
    }

    private static void TestTemplateMatchingBatchAutoLabelSaveAndSkip()
    {
        string root = CreateTempRoot();
        try
        {
            var data = new CData();
            data.ConfigureOutputRoot(root);
            data.ProjectSettings.YoloDataset.ValidationPercent = 0;
            data.ProjectSettings.YoloDataset.TestPercent = 0;
            data.ClassNamedList.Clear();
            var partClass = new CClassItem { Text = "Part", DrawColor = Color.Blue };
            data.ClassNamedList.Add(partClass);
            data.EnsureYoloOutputDirectories();

            string sourceDirectory = Path.Combine(root, "source");
            Directory.CreateDirectory(sourceDirectory);
            string activeImagePath = Path.Combine(sourceDirectory, "active-template.png");
            string targetImagePath = Path.Combine(sourceDirectory, "batch-target.png");
            string existingImagePath = Path.Combine(sourceDirectory, "skip-existing.png");

            using (Bitmap activeImage = CreateTemplateBatchAutoLabelImage(new Point(12, 12)))
            using (Bitmap targetImage = CreateTemplateBatchAutoLabelImage(new Point(56, 34)))
            using (Bitmap existingImage = CreateTemplateBatchAutoLabelImage(new Point(72, 48)))
            {
                activeImage.Save(activeImagePath, System.Drawing.Imaging.ImageFormat.Png);
                targetImage.Save(targetImagePath, System.Drawing.Imaging.ImageFormat.Png);
                existingImage.Save(existingImagePath, System.Drawing.Imaging.ImageFormat.Png);
            }

            string existingLabelPath = Path.Combine(root, "data", "train", "labels", "skip-existing.txt");
            File.WriteAllText(existingLabelPath, "sentinel");
            data.LastSelectImageName = Path.GetFileNameWithoutExtension(activeImagePath);
            data.LastSelectImagePath = activeImagePath;

            var service = new TemplateMatchingBatchAutoLabelService();
            IReadOnlyList<string> queue = service.BuildUnlabeledImagePathQueue(
                new[] { activeImagePath, targetImagePath, targetImagePath, existingImagePath },
                data,
                activeImagePath);

            AssertEqual(1, queue.Count);
            AssertEqual(targetImagePath, queue[0]);

            using Bitmap templateImage = CreateTemplateBatchAutoLabelPattern();
            var options = new TemplateMatchingAutoLabelOptions
            {
                MinimumScore = 0.7D,
                MaximumCandidates = 3,
                ExcludeSourceRegion = false
            };

            TemplateMatchingBatchAutoLabelItemResult saved = service.MatchAndSaveImage(
                targetImagePath,
                templateImage,
                partClass,
                partClass.Text,
                data,
                options,
                CancellationToken.None);

            AssertTrue(saved.Saved, $"template batch target should be saved: {saved.Message}");
            AssertTrue(saved.CandidateCount > 0, "template batch target should save at least one matched box");

            string targetLabelPath = Path.Combine(root, "data", "train", "labels", "batch-target.txt");
            string targetPngPath = Path.Combine(root, "data", "train", "images", "batch-target.png");
            string targetJpegPath = Path.Combine(root, "data", "train", "images", "batch-target.jpeg");
            AssertTrue(File.Exists(targetLabelPath), "template batch target label was not created");
            AssertTrue(File.Exists(targetPngPath), "template batch should preserve the target source PNG extension");
            AssertTrue(!File.Exists(targetJpegPath), "template batch should not create a duplicate JPEG copy for a PNG source");

            IReadOnlyDictionary<string, List<Rectangle>> loaded = YoloAnnotationService.LoadAnnotationRectanglesForImage(
                targetPngPath,
                data.ClassNamedList,
                data,
                new Size(120, 90));

            AssertTrue(loaded.TryGetValue("Part", out List<Rectangle> loadedPartRects) && loadedPartRects.Count > 0, "saved template batch label should reload as the selected class");

            TemplateMatchingBatchAutoLabelItemResult skipped = service.MatchAndSaveImage(
                existingImagePath,
                templateImage,
                partClass,
                partClass.Text,
                data,
                options,
                CancellationToken.None);

            AssertTrue(!skipped.Saved, "template batch should not save an image that already has a label file");
            AssertEqual("label file already exists", skipped.Message);
            AssertEqual("sentinel", File.ReadAllText(existingLabelPath));
        }
        finally
        {
            DeleteTempRoot(root);
        }
    }

    private static void TestTemplateMatchingAutoLabelGuide()
    {
        string root = FindRepositoryRoot();
        var viewModel = new WpfTemplateMatchingAutoLabelViewModel();
        using var activeImage = new Bitmap(40, 40);
        var presentationService = new WpfTemplateMatchingAutoLabelPresentationService();
        AssertTrue(
            presentationService.BuildTemplateRegisteredStatus("Part", new Rectangle(1, 2, 30, 40)).Contains("Part 30x40", StringComparison.Ordinal),
            "template presentation service should format the registered template size and class");
        AssertTrue(
            presentationService.BuildApplyResultStatus(2, 2).Contains("라벨 저장", StringComparison.Ordinal),
            "template presentation service should direct the operator to save current-image draft labels");
        AssertTrue(
            presentationService.BuildBatchCompletionCommandStatus(false, 1, 2, 3, 4).Contains("저장 1장", StringComparison.Ordinal),
            "template presentation service should summarize batch auto-save counts");
        AssertTrue(
            presentationService.BuildGuideBody("템플릿 안내").Contains("사용 순서", StringComparison.Ordinal),
            "template presentation service should own the reusable guide step text");

        var noImageHost = new TemplateAutoLabelGuideHost
        {
            HasActiveAutoLabelImageValue = false,
            ActiveAutoLabelImageValue = activeImage
        };
        viewModel.ConfigureHost(noImageHost);
        viewModel.RunCurrentImage();
        AssertEqual(1, noImageHost.GuideCount);
        AssertTrue(noImageHost.LastGuideTitle.Contains("\uC774\uBBF8\uC9C0", StringComparison.Ordinal), "template guide should name the missing image");
        AssertTrue(noImageHost.LastGuideMessage.Contains("\uC0AC\uC6A9 \uC21C\uC11C", StringComparison.Ordinal), "template guide should include direct usage steps");
        AssertTrue(noImageHost.LastGuideMessage.Contains("현재 이미지 라벨 초안 생성", StringComparison.Ordinal), "template guide should name the current-image draft-label action");
        AssertTrue(noImageHost.LastGuideMessage.Contains("전체 이미지 자동 저장", StringComparison.Ordinal), "template guide should name the batch auto-save action");
        AssertTrue(noImageHost.LastGuideMessage.Contains("라벨 초안", StringComparison.Ordinal), "template guide should distinguish template drafts from AI candidates");
        AssertTrue(noImageHost.LastGuideMessage.Contains("바로 저장", StringComparison.Ordinal), "template guide should explain that batch mode saves unlabeled images directly");
        AssertTrue(noImageHost.LastGuideMessage.Contains("\uAC80\uD1A0", StringComparison.Ordinal), "template guide should include the review step");
        AssertTrue(noImageHost.LastGuideMessage.Contains("\uB77C\uBCA8 \uC800\uC7A5", StringComparison.Ordinal), "template guide should include the final save step");
        AssertTrue(noImageHost.LastGlobalStatus.Contains("\uC774\uBBF8\uC9C0", StringComparison.Ordinal), "template guide should update visible inference status");

        var noSourceHost = new TemplateAutoLabelGuideHost
        {
            HasActiveAutoLabelImageValue = true,
            ActiveAutoLabelImageValue = activeImage,
            ActiveAutoLabelImagePathValue = "no-source.png",
            HasTemplateSource = false
        };
        viewModel.ConfigureHost(noSourceHost);
        viewModel.RunCurrentImage();
        AssertEqual(1, noSourceHost.GuideCount);
        AssertTrue(noSourceHost.LastGuideTitle.Contains("\uB77C\uBCA8", StringComparison.Ordinal), "template guide should name the missing source label");
        AssertTrue(noSourceHost.LastGuideMessage.Contains("\uAC1D\uCCB4 \uAC80\uD1A0", StringComparison.Ordinal), "template guide should tell the operator where to select the source box");

        viewModel.RunBatch();
        AssertEqual(2, noSourceHost.GuideCount);
        AssertTrue(noSourceHost.LastGuideMessage.Contains("\uB77C\uBCA8 \uC5C6\uB294", StringComparison.Ordinal), "template batch guide should explain the unlabeled queue target");

        using var templateSourceImage = CreateTemplateCurrentImageSource();
        var sourceHost = new TemplateAutoLabelGuideHost
        {
            HasActiveAutoLabelImageValue = true,
            ActiveAutoLabelImageValue = templateSourceImage,
            ActiveAutoLabelImagePathValue = "template-source.png",
            HasTemplateSource = true,
            TemplateSourceBounds = new Rectangle(8, 10, 24, 22)
        };
        viewModel.ConfigureHost(sourceHost);
        viewModel.RunCurrentImage();
        AssertEqual(0, sourceHost.GuideCount);
        AssertTrue(!sourceHost.ApplyCandidatesCalled, "template source click should register the template instead of applying it to the same image");
        AssertTrue(sourceHost.LastGlobalStatus.Contains("\uD15C\uD50C\uB9BF \uB4F1\uB85D", StringComparison.Ordinal), "template source click should show the registered state");
        AssertTrue(sourceHost.LastGlobalStatus.Contains("라벨 초안 생성", StringComparison.Ordinal), "template source registration should point to the next draft-label generation step");

        using var templateTargetImage = CreateTemplateTargetImage();
        var targetHost = new TemplateAutoLabelGuideHost
        {
            HasActiveAutoLabelImageValue = true,
            ActiveAutoLabelImageValue = templateTargetImage,
            ActiveAutoLabelImagePathValue = "template-target.png",
            HasTemplateSource = false
        };
        viewModel.ConfigureHost(targetHost);
        viewModel.RunCurrentImage();
        AssertTrue(targetHost.ApplyCandidatesCalled, "registered template should be applied on a different image without requiring a target-side source box");
        AssertTrue(targetHost.LastApplySucceeded, "registered template apply should not be marked as failed");
        AssertTrue(targetHost.LastCandidateCount > 0, "registered template should find the shifted target pattern");
        AssertTrue(targetHost.LastCandidates.Any(candidate => Math.Abs(candidate.X - 44) <= 4 && Math.Abs(candidate.Y - 42) <= 4),
            "registered template should find the target pattern near the shifted location");
        AssertTrue(targetHost.LastGlobalStatus.Contains("템플릿 라벨 초안", StringComparison.Ordinal), "registered template apply should report draft-label creation");
        AssertTrue(targetHost.LastGlobalStatus.Contains("\uB77C\uBCA8 \uC800\uC7A5", StringComparison.Ordinal), "registered template apply should direct the operator to save labels after review");
        AssertTrue(!targetHost.LastGlobalStatus.Contains("AI \uD6C4\uBCF4", StringComparison.Ordinal), "template apply status should not look like AI-candidate review");

        string batchRoot = CreateTempRoot();
        try
        {
            string imageRoot = Path.Combine(batchRoot, "images");
            string outputRoot = Path.Combine(batchRoot, "dataset");
            Directory.CreateDirectory(imageRoot);

            string batchSourcePath = Path.Combine(imageRoot, "template-batch-source.png");
            string batchTargetPath = Path.Combine(imageRoot, "template-batch-target.png");
            using (Bitmap batchSourceImage = CreateTemplateCurrentImageSource())
            using (Bitmap batchTargetImage = CreateTemplateTargetImage())
            {
                batchSourceImage.Save(batchSourcePath, System.Drawing.Imaging.ImageFormat.Png);
                batchTargetImage.Save(batchTargetPath, System.Drawing.Imaging.ImageFormat.Png);
            }

            var batchData = new CData();
            batchData.ConfigureOutputRoot(outputRoot);
            batchData.ProjectSettings.YoloDataset.ValidationPercent = 0;
            batchData.ProjectSettings.YoloDataset.TestPercent = 0;
            batchData.ProjectSettings.PythonModel.ImageRootPath = imageRoot;
            batchData.ClassNamedList.Clear();
            batchData.ClassNamedList.Add(new CClassItem { Text = "Part", DrawColor = Color.Blue });
            batchData.EnsureYoloOutputDirectories();

            var batchViewModel = new WpfTemplateMatchingAutoLabelViewModel();
            using var batchTemplateSourceImage = CreateTemplateCurrentImageSource();
            var batchSourceHost = new TemplateAutoLabelGuideHost
            {
                HasActiveAutoLabelImageValue = true,
                ActiveAutoLabelImageValue = batchTemplateSourceImage,
                ActiveAutoLabelImagePathValue = batchSourcePath,
                HasTemplateSource = true,
                TemplateSourceBounds = new Rectangle(8, 10, 24, 22),
                AutoLabelDataValue = batchData
            };
            batchViewModel.ConfigureHost(batchSourceHost);
            batchViewModel.RunCurrentImage();

            using var batchActiveImage = CreateTemplateTargetImage();
            var batchHost = new TemplateAutoLabelGuideHost
            {
                HasActiveAutoLabelImageValue = true,
                ActiveAutoLabelImageValue = batchActiveImage,
                ActiveAutoLabelImagePathValue = batchTargetPath,
                HasTemplateSource = false,
                AutoLabelDataValue = batchData,
                AllQueueItems = new[]
                {
                    WpfImageQueueItem.CreateShell(batchSourcePath),
                    WpfImageQueueItem.CreateShell(batchTargetPath)
                }
            };

            batchViewModel.ConfigureHost(batchHost);
            batchViewModel.RunBatch();
            AssertTrue(WaitUntil(() => batchHost.BatchCompleted, TimeSpan.FromSeconds(5)), "registered template batch should complete");
            AssertEqual(1, batchHost.StartedBatchTotalCount);
            AssertEqual(1, batchHost.BatchCompletedCount);
            AssertEqual(1, batchHost.BatchResults.Count);
            AssertTrue(batchHost.BatchResults[0].Saved, $"registered template batch should save the target label: {batchHost.BatchResults[0].Message}");

            string batchTargetLabelPath = Path.Combine(outputRoot, "data", "train", "labels", "template-batch-target.txt");
            string batchSourceLabelPath = Path.Combine(outputRoot, "data", "train", "labels", "template-batch-source.txt");
            AssertTrue(File.Exists(batchTargetLabelPath), "registered template batch should create a label file for the unlabeled target image");
            AssertTrue(!File.Exists(batchSourceLabelPath), "registered template batch should not relabel the registered source image");
        }
        finally
        {
            DeleteTempRoot(batchRoot);
        }

        using var noMatchImage = CreateSolidBitmap(40, 40, Color.FromArgb(230, 230, 230));
        var noCandidateHost = new TemplateAutoLabelGuideHost
        {
            HasActiveAutoLabelImageValue = true,
            ActiveAutoLabelImageValue = noMatchImage,
            ActiveAutoLabelImagePathValue = "template-no-match.png",
            HasTemplateSource = false
        };
        viewModel.ConfigureHost(noCandidateHost);
        viewModel.RunCurrentImage();
        AssertTrue(noCandidateHost.ApplyCandidatesCalled, "registered template no-match result should still clear stale candidate state");
        AssertTrue(noCandidateHost.LastApplySucceeded, "registered template no-match result should not be marked as a failed detection");
        AssertEqual(0, noCandidateHost.LastCandidateCount);
        AssertTrue(noCandidateHost.LastGlobalStatus.Contains("\uCC3E\uC9C0 \uBABB\uD588", StringComparison.Ordinal), "registered template no-match result should explain that no target position was found");
        AssertTrue(noCandidateHost.LastGlobalIsWarning, "registered template no-match result should use the warning status style");

        string projectSource = File.ReadAllText(Path.Combine(root, "OpenVisionLab.LabelingStudio.csproj"));
        string solutionSource = File.ReadAllText(Path.Combine(root, "OpenVisionLab.LabelingStudio.sln"));
        string templateCommandsSource = File.ReadAllText(Path.Combine(root, "0. UI", "9) WPF", "Views", "WpfLabelingShellWindow.TemplateMatchingCommands.cs"));
        string templateViewModelSource = File.ReadAllText(Path.Combine(root, "0. UI", "9) WPF", "ViewModels", "WpfTemplateMatchingAutoLabelViewModel.cs"));
        string templatePresentationPath = Path.Combine(root, "0. UI", "9) WPF", "Services", "WpfTemplateMatchingAutoLabelPresentationService.cs");
        string dialogControlPath = Path.Combine(root, "OpenVisionLab", "Library", "OpenVisionLab.Wpf.MessageDialogs", "WpfMessageDialogControl.xaml");
        AssertTrue(File.Exists(templatePresentationPath), "template auto-label wording should live in a WPF presentation service");
        AssertTrue(templateViewModelSource.Contains("WpfTemplateMatchingAutoLabelPresentationService", StringComparison.Ordinal), "template auto-label ViewModel should use the presentation service for status text");
        AssertTrue(!templateViewModelSource.Contains("전체 이미지 템플릿 자동 저장 시작:", StringComparison.Ordinal), "template auto-label ViewModel should not inline the batch start status template");
        AssertTrue(File.Exists(dialogControlPath), "template guide should use the reusable WPF message dialog UserControl project");
        AssertTrue(projectSource.Contains("OpenVisionLab.Wpf.MessageDialogs", StringComparison.Ordinal), "app project should reference the reusable WPF message dialog library");
        AssertTrue(solutionSource.Contains("OpenVisionLab.Wpf.MessageDialogs", StringComparison.Ordinal), "solution should include the reusable WPF message dialog library project");
        AssertTrue(templateCommandsSource.Contains("OpenVisionLab.Wpf.MessageDialogs", StringComparison.Ordinal), "template guide host should import the reusable WPF dialog namespace");
        AssertTrue(templateCommandsSource.Contains("WpfMessageDialog.ShowInfo", StringComparison.Ordinal), "template guide host should show the reusable WPF dialog");
        AssertTrue(!templateCommandsSource.Contains("MessageBox.Show", StringComparison.Ordinal), "template guide host should not fall back to the stock WPF MessageBox");
    }

    private static Bitmap CreateTemplateCurrentImageSource()
    {
        Bitmap image = CreateSolidBitmap(80, 80, Color.FromArgb(230, 230, 230));
        using Graphics graphics = Graphics.FromImage(image);
        DrawTemplatePattern(graphics, 8, 10);
        graphics.FillRectangle(Brushes.Red, 52, 48, 12, 16);
        graphics.DrawLine(Pens.Blue, 4, 72, 72, 8);
        return image;
    }

    private static Bitmap CreateTemplateTargetImage()
    {
        Bitmap image = CreateSolidBitmap(80, 80, Color.FromArgb(230, 230, 230));
        using Graphics graphics = Graphics.FromImage(image);
        DrawTemplatePattern(graphics, 44, 42);
        graphics.FillRectangle(Brushes.Red, 6, 6, 12, 16);
        graphics.DrawLine(Pens.Blue, 3, 75, 75, 12);
        return image;
    }

    private static void DrawTemplatePattern(Graphics graphics, int x, int y)
    {
        graphics.FillRectangle(Brushes.Black, x, y, 24, 22);
        graphics.FillEllipse(Brushes.DimGray, x + 4, y + 3, 15, 14);
        graphics.DrawLine(Pens.White, x + 2, y + 2, x + 21, y + 18);
        graphics.DrawLine(Pens.LightGray, x + 5, y + 19, x + 20, y + 4);
        graphics.FillRectangle(Brushes.White, x + 14, y + 6, 4, 5);
    }

    private static void TestWpfTemplateCurrentImageNoCandidatePreservesSavedLabelStatus()
    {
        if (System.Windows.Application.Current == null)
        {
            _ = new System.Windows.Application
            {
                ShutdownMode = System.Windows.ShutdownMode.OnExplicitShutdown
            };
        }

        CData previousData = CGlobal.Inst.Data;
        string root = CreateTempRoot();
        try
        {
            string imageRoot = Path.Combine(root, "images");
            string outputRoot = Path.Combine(root, "dataset");
            Directory.CreateDirectory(imageRoot);
            string imagePath = Path.Combine(imageRoot, "template-current.png");
            using (Bitmap image = CreateTemplateCurrentImageSource())
            {
                image.Save(imagePath, System.Drawing.Imaging.ImageFormat.Png);
            }

            var data = new CData();
            data.ConfigureOutputRoot(outputRoot);
            data.ProjectSettings.DatasetPurpose = LabelingDatasetPurpose.ObjectDetection;
            data.ProjectSettings.PythonModel.ImageRootPath = imageRoot;
            data.ClassNamedList.Clear();
            data.ClassNamedList.Add(new CClassItem { Text = "OK", DrawColor = Color.LimeGreen });
            CGlobal.Inst.Data = data;

            WpfLabelingShellWindow window = new WpfLabelingShellWindow();
            try
            {
                AssertTrue(window.TryLoadImage(imagePath, populateQueue: true, refreshQueueDetails: false), "WPF template no-candidate test image load failed");
                PumpWpfDispatcher(TimeSpan.FromMilliseconds(20));

                var manualRect = new CanvasRect<float>(5, 6, 15, 14)
                {
                    UniqueId = "template-current-source",
                    ShapeKind = CanvasRoiShapeKind.Rectangle
                };
                InvokePrivateResult<object>(
                    window,
                    "MainCanvasViewModel_RoiAdded",
                    window.MainCanvasViewModel,
                    new OpenVisionLab.ImageCanvas.Model.RoiChangedEventArgs { RoiRect = manualRect });

                object[] saveArgs = { 0 };
                AssertTrue(InvokePrivateResult<bool>(window, "SaveCurrentAnnotations", saveArgs), "template source label should be saveable before no-candidate run");
                AssertEqual(1, (int)saveArgs[0]);
                InvokePrivateResult<object>(window, "RefreshActiveImageQueueStatus", false);
                PumpWpfDispatcher(TimeSpan.FromMilliseconds(20));

                WpfImageQueueItem item = window.ImageQueueItems.FirstOrDefault(queueItem =>
                    string.Equals(queueItem.ImagePath, imagePath, StringComparison.OrdinalIgnoreCase));
                AssertTrue(item != null, "template no-candidate test queue item was not created");
                AssertEqual(YoloImageReviewState.Confirmed, item.ReviewState);

                ((IWpfTemplateMatchingAutoLabelHost)window).ApplyAutoLabelCandidates(Array.Empty<YoloWorkerSmokeCandidate>(), succeeded: true);
                PumpWpfDispatcher(TimeSpan.FromMilliseconds(20));

                item = window.ImageQueueItems.FirstOrDefault(queueItem =>
                    string.Equals(queueItem.ImagePath, imagePath, StringComparison.OrdinalIgnoreCase));
                AssertTrue(item != null, "template no-candidate test queue item disappeared after applying result");
                AssertEqual(YoloImageReviewState.Confirmed, item.ReviewState);
                AssertTrue(item.LabelStatus.Contains("1", StringComparison.Ordinal), "template no-candidate should keep the saved label count visible");
                AssertTrue(!item.DetectStatus.Contains("\uAC80\uCD9C\uC5C6\uC74C", StringComparison.Ordinal), "template no-candidate should not overwrite a saved label row as no-candidate detection");

                WpfCandidateReviewStateService candidateState = GetPrivateField<WpfCandidateReviewStateService>(window, "candidateReviewState");
                AssertEqual(0, candidateState.PendingCandidates.Count);

                int added = ((IWpfTemplateMatchingAutoLabelHost)window).ApplyAutoLabelCandidates(
                    new[]
                    {
                        new YoloWorkerSmokeCandidate
                        {
                            Index = 1,
                            ClassName = "OK",
                            Confidence = 0.93D,
                            X = 38,
                            Y = 42,
                            Width = 18,
                            Height = 16
                        }
                    },
                    succeeded: true);
                AssertEqual(1, added);
                var manualRois = GetPrivateField<List<Rectangle>>(window, "manualRois");
                AssertTrue(manualRois.Any(bounds => bounds.X == 38 && bounds.Y == 42 && bounds.Width == 18 && bounds.Height == 16),
                    "template candidate should be materialized as a manual label on the current image");
                AssertTrue(window.CanvasPanelViewModel.IsAnnotationSaveEnabled, "template-added manual labels should require an explicit label save");
            }
            finally
            {
                window.Close();
            }
        }
        finally
        {
            CGlobal.Inst.Data = previousData;
            DeleteTempRoot(root);
        }
    }

    private sealed class TemplateAutoLabelGuideHost : IWpfTemplateMatchingAutoLabelHost
    {
        public bool HasActiveAutoLabelImageValue { get; set; }
        public Bitmap ActiveAutoLabelImageValue { get; set; }
        public string ActiveAutoLabelImagePathValue { get; set; } = string.Empty;
        public bool HasTemplateSource { get; set; }
        public Rectangle? TemplateSourceBounds { get; set; }
        public int GuideCount { get; private set; }
        public string LastGuideTitle { get; private set; } = string.Empty;
        public string LastGuideMessage { get; private set; } = string.Empty;
        public string LastGlobalStatus { get; private set; } = string.Empty;
        public bool LastGlobalIsWarning { get; private set; }
        public bool ApplyCandidatesCalled { get; private set; }
        public bool LastApplySucceeded { get; private set; }
        public int LastCandidateCount { get; private set; }
        public IReadOnlyList<YoloWorkerSmokeCandidate> LastCandidates { get; private set; } = Array.Empty<YoloWorkerSmokeCandidate>();
        public CData AutoLabelDataValue { get; set; } = new CData();
        public IReadOnlyList<WpfImageQueueItem> AllQueueItems { get; set; } = Array.Empty<WpfImageQueueItem>();
        public IReadOnlyList<TemplateMatchingBatchAutoLabelItemResult> BatchResults { get; private set; } = Array.Empty<TemplateMatchingBatchAutoLabelItemResult>();
        public bool BatchCompleted { get; private set; }
        public int StartedBatchTotalCount { get; private set; }
        public int BatchCompletedCount { get; private set; }

        public bool IsAutoLabelBusy => false;
        public bool HasActiveAutoLabelImage => HasActiveAutoLabelImageValue;
        public Bitmap ActiveAutoLabelImage => ActiveAutoLabelImageValue;
        public string ActiveAutoLabelImagePath => ActiveAutoLabelImagePathValue;
        public CData AutoLabelData => AutoLabelDataValue;
        public int MaximumTemplateMatchingCandidateCount => 20;

        public bool TryResolveTemplateMatchingSource(out Rectangle templateBounds, out string className)
        {
            templateBounds = HasTemplateSource ? TemplateSourceBounds ?? new Rectangle(1, 1, 10, 10) : Rectangle.Empty;
            className = "Part";
            return HasTemplateSource;
        }

        public CClassItem EnsureAutoLabelClassItem(string className)
            => new CClassItem { Text = string.IsNullOrWhiteSpace(className) ? "Part" : className, DrawColor = Color.Blue };

        public IReadOnlyList<WpfImageQueueItem> GetVisibleAutoLabelQueueItems()
            => AllQueueItems;

        public IReadOnlyList<WpfImageQueueItem> GetAllAutoLabelQueueItems()
            => AllQueueItems;

        public IReadOnlyList<WpfImageQueueItem> BuildAutoLabelBatchQueue(IEnumerable<WpfImageQueueItem> items)
            => (items ?? Array.Empty<WpfImageQueueItem>()).ToList();

        public void AppendAutoLabelLog(string message)
        {
        }

        public void ShowAutoLabelGuide(string title, string message)
        {
            GuideCount++;
            LastGuideTitle = title ?? string.Empty;
            LastGuideMessage = message ?? string.Empty;
        }

        public int ApplyAutoLabelCandidates(IReadOnlyList<YoloWorkerSmokeCandidate> candidates, bool succeeded)
        {
            ApplyCandidatesCalled = true;
            LastApplySucceeded = succeeded;
            LastCandidateCount = candidates?.Count ?? 0;
            LastCandidates = (candidates ?? Array.Empty<YoloWorkerSmokeCandidate>()).ToList();
            return LastCandidateCount;
        }

        public void SetAutoLabelPythonStatus(string text)
        {
        }

        public void SetAutoLabelCommandStatus(string text, bool isBusy)
        {
        }

        public void SetAutoLabelGlobalInferenceStatus(string text, bool isBusy, bool isWarning = false)
        {
            LastGlobalStatus = text ?? string.Empty;
            LastGlobalIsWarning = isWarning;
        }

        public CancellationToken StartAutoLabelBatch(int totalCount, string scopeText)
        {
            StartedBatchTotalCount = totalCount;
            BatchCompleted = false;
            BatchResults = Array.Empty<TemplateMatchingBatchAutoLabelItemResult>();
            return CancellationToken.None;
        }

        public void MarkAutoLabelBatchItemRequested(WpfImageQueueItem item)
        {
        }

        public void UpdateAutoLabelBatchProgress(string scopeText, string currentFileName, int completedCount, int totalCount)
        {
        }

        public void ApplyAutoLabelBatchResult(WpfImageQueueItem item, TemplateMatchingBatchAutoLabelItemResult result, bool saveReviewStatus)
        {
            BatchResults = BatchResults.Concat(new[] { result }).ToList();
        }

        public void SaveAutoLabelReviewStatus()
        {
        }

        public void CompleteAutoLabelBatch(bool canceled, int completedCount, int totalCount, string scopeText)
        {
            BatchCompleted = true;
            BatchCompletedCount = completedCount;
        }

        public void NotifyAutoLabelDataChanged()
        {
        }

        public Task YieldAutoLabelBatchFrameAsync(CancellationToken token)
            => Task.CompletedTask;
    }

    private static Bitmap CreateTemplateBatchAutoLabelImage(params Point[] patternOrigins)
    {
        Bitmap image = CreateSolidBitmap(120, 90, Color.FromArgb(235, 235, 235));
        using Graphics graphics = Graphics.FromImage(image);
        using Bitmap pattern = CreateTemplateBatchAutoLabelPattern();
        foreach (Point origin in patternOrigins ?? Array.Empty<Point>())
        {
            graphics.DrawImageUnscaled(pattern, origin);
        }

        return image;
    }

    private static Bitmap CreateTemplateBatchAutoLabelPattern()
    {
        var pattern = new Bitmap(24, 18);
        using Graphics graphics = Graphics.FromImage(pattern);
        graphics.Clear(Color.FromArgb(235, 235, 235));
        graphics.FillRectangle(Brushes.Black, 3, 4, 18, 9);
        graphics.FillRectangle(Brushes.White, 7, 6, 5, 4);
        graphics.FillRectangle(Brushes.Red, 16, 3, 3, 12);
        graphics.DrawLine(Pens.Blue, 2, 15, 21, 15);
        graphics.DrawRectangle(Pens.DarkGreen, 1, 1, 22, 16);
        return pattern;
    }

    private static void TestSegmentationAnnotationFileWrite()
    {
        string root = CreateTempRoot();
        string externalRoot = root + "-segments";
        try
        {
            var data = new CData();
            data.ConfigureOutputRoot(root);
            data.ProjectSettings.YoloDataset.ValidationPercent = 0;
            data.ClassNamedList.Add(new CClassItem { Text = "OK", DrawColor = Color.Green });
            data.ClassNamedList.Add(new CClassItem { Text = "Defect", DrawColor = Color.Red });

            using var image = new Bitmap(20, 20);
            var externalSegmentFile = new SegmentationAnnotationFile
            {
                Version = 2,
                ImageName = "shared.png",
                ImageWidth = 20,
                ImageHeight = 20,
                Polygons = new List<SegmentationPolygonRecord>
                {
                    new SegmentationPolygonRecord
                    {
                        ClassIndex = 1,
                        ClassName = "Defect",
                        Points = new List<SegmentationPointRecord>
                        {
                            new SegmentationPointRecord { X = 2, Y = 2 },
                            new SegmentationPointRecord { X = 12, Y = 2 },
                            new SegmentationPointRecord { X = 12, Y = 12 },
                            new SegmentationPointRecord { X = 2, Y = 12 }
                        }
                    }
                }
            };
            string reusedImagesDirectory = Path.Combine(externalRoot, "Images");
            string reusedSegmentsDirectory = Path.Combine(externalRoot, "segments");
            Directory.CreateDirectory(reusedImagesDirectory);
            Directory.CreateDirectory(reusedSegmentsDirectory);
            string reusedImagePath = Path.Combine(reusedImagesDirectory, "shared.png");
            string reusedSiblingSegmentPath = Path.Combine(reusedSegmentsDirectory, "shared.json");
            string reusedSidecarSegmentPath = Path.Combine(reusedImagesDirectory, "shared.segments.json");
            File.WriteAllText(reusedImagePath, string.Empty);
            File.WriteAllText(reusedSiblingSegmentPath, JsonConvert.SerializeObject(externalSegmentFile, Formatting.Indented));
            File.WriteAllText(reusedSidecarSegmentPath, JsonConvert.SerializeObject(externalSegmentFile, Formatting.Indented));

            IReadOnlyDictionary<string, List<LabelingSegmentationObject>> legacySegments =
                YoloSegmentationAnnotationService.LoadSegmentationObjectsForImage(
                    reusedImagePath,
                    data.ClassNamedList,
                    null,
                    image.Size);
            AssertEqual(1, legacySegments["Defect"].Count);

            IReadOnlyDictionary<string, List<LabelingSegmentationObject>> isolatedSegments =
                YoloSegmentationAnnotationService.LoadSegmentationObjectsForImage(
                    reusedImagePath,
                    data.ClassNamedList,
                    data,
                    image.Size);
            AssertEqual(0, isolatedSegments.Count);

            string activeSharedSegmentPath = Path.Combine(root, "data", "train", "segments", "shared.json");
            Directory.CreateDirectory(Path.GetDirectoryName(activeSharedSegmentPath));
            File.WriteAllText(activeSharedSegmentPath, JsonConvert.SerializeObject(externalSegmentFile, Formatting.Indented));
            IReadOnlyDictionary<string, List<LabelingSegmentationObject>> activeSegments =
                YoloSegmentationAnnotationService.LoadSegmentationObjectsForImage(
                    reusedImagePath,
                    data.ClassNamedList,
                    data,
                    image.Size);
            AssertEqual(1, activeSegments["Defect"].Count);

            var segments = new Dictionary<string, List<LabelingSegmentationObject>>
            {
                ["Defect"] = new List<LabelingSegmentationObject>
                {
                    new LabelingSegmentationObject(
                        new[]
                        {
                            new Point(2, 2),
                            new Point(12, 2),
                            new Point(12, 12),
                            new Point(2, 12)
                        },
                        data.ClassNamedList[1])
                    {
                        CutoutPolygons = new List<List<Point>>
                        {
                            new List<Point>
                            {
                                new Point(6, 6),
                                new Point(9, 6),
                                new Point(9, 9),
                                new Point(6, 9)
                            }
                        }
                    }
                }
            };

            YoloSegmentationAnnotationService.SaveSegmentationAnnotations(
                "seg-sample.png",
                image,
                segments,
                data.ClassNamedList,
                data);

            string maskPath = Path.Combine(root, "data", "train", "masks", "seg-sample.png");
            string segmentPath = Path.Combine(root, "data", "train", "segments", "seg-sample.json");
            AssertTrue(File.Exists(maskPath), "segmentation mask file was not saved");
            AssertTrue(File.Exists(segmentPath), "segmentation polygon json was not saved");

            using (var mask = new Bitmap(maskPath))
            {
                AssertEqual(2, mask.GetPixel(5, 5).R);
                AssertEqual(0, mask.GetPixel(7, 7).R);
                AssertEqual(0, mask.GetPixel(18, 18).R);
            }

            IReadOnlyDictionary<string, List<List<Point>>> loaded = YoloSegmentationAnnotationService.LoadSegmentationPolygons(
                segmentPath,
                data.ClassNamedList,
                image.Size);
            AssertTrue(loaded.ContainsKey("Defect"), "segmentation polygon class was not restored");
            AssertEqual(1, loaded["Defect"].Count);
            AssertEqual(new Point(2, 2), loaded["Defect"][0][0]);
            IReadOnlyDictionary<string, List<LabelingSegmentationObject>> loadedObjects = YoloSegmentationAnnotationService.LoadSegmentationObjects(
                segmentPath,
                data.ClassNamedList,
                image.Size);
            AssertEqual(1, loadedObjects["Defect"][0].CutoutPolygons.Count);
            SegmentationAnnotationFile annotationFile = JsonConvert.DeserializeObject<SegmentationAnnotationFile>(File.ReadAllText(segmentPath));
            AssertEqual(2, annotationFile.Version);

            var maskData = new byte[20 * 20];
            for (int y = 5; y < 11; y++)
            {
                int rowOffset = y * 20;
                for (int x = 4; x < 12; x++)
                {
                    maskData[rowOffset + x] = 255;
                }
            }

            var rasterSegments = new Dictionary<string, List<LabelingSegmentationObject>>
            {
                ["Defect"] = new List<LabelingSegmentationObject>
                {
                    new LabelingSegmentationObject
                    {
                        ClassName = "Defect",
                        ClassItem = data.ClassNamedList[1],
                        MaskData = maskData,
                        MaskSize = new Size(20, 20)
                    }
                }
            };

            YoloSegmentationAnnotationService.SaveSegmentationAnnotations(
                "seg-mask.png",
                image,
                rasterSegments,
                data.ClassNamedList,
                data);

            string rasterSegmentPath = Path.Combine(root, "data", "train", "segments", "seg-mask.json");
            SegmentationAnnotationFile rasterAnnotation = JsonConvert.DeserializeObject<SegmentationAnnotationFile>(File.ReadAllText(rasterSegmentPath));
            AssertEqual(1, rasterAnnotation.Polygons.Count);
            Rectangle rasterBounds = SegmentationGeometry.GetBounds(
                rasterAnnotation.Polygons[0].Points.Select(point => new Point(point.X, point.Y)));
            AssertEqual(new Rectangle(4, 5, 8, 6), rasterBounds);
        }
        finally
        {
            DeleteTempRoot(root);
            DeleteDirectoryIfExists(externalRoot);
        }
    }

    private static void TestSegmentationGeometryBoxConversion()
    {
        List<Point> polygon = SegmentationGeometry.RectangleToPolygon(new Rectangle(-2, 3, 12, 8), new Size(20, 20));

        AssertEqual(4, polygon.Count);
        AssertEqual(new Rectangle(0, 3, 10, 8), SegmentationGeometry.GetBounds(polygon));
        AssertTrue(SegmentationGeometry.ContainsPoint(polygon, new Point(5, 5)), "box polygon should contain its center");
        AssertTrue(!SegmentationGeometry.ContainsPoint(polygon, new Point(12, 5)), "box polygon should not contain outside pixels");

        List<Point> noisyLine = SegmentationGeometry.NormalizePolygon(
            new[]
            {
                new Point(1, 1),
                new Point(2, 1),
                new Point(3, 1),
                new Point(10, 1),
                new Point(10, 8),
                new Point(1, 8)
            },
            new Size(20, 20),
            minimumDistance: 1,
            simplificationTolerance: 2D);
        AssertTrue(noisyLine.Count < 6, "segmentation simplification should remove redundant drag points");

        List<Point> brush = SegmentationGeometry.CircleToPolygon(new Point(10, 10), 4, new Size(30, 30));
        AssertTrue(brush.Count >= 8, "brush polygon should create editable circle points");
        AssertTrue(SegmentationGeometry.IntersectsCircle(brush, new Point(10, 10), 3), "brush polygon should intersect its center circle");
        List<List<Point>> brushStroke = SegmentationGeometry.BrushStrokeToPolygons(
            new[]
            {
                new Point(10, 10),
                new Point(14, 10),
                new Point(18, 10)
            },
            4,
            new Size(40, 30));
        AssertEqual(1, brushStroke.Count);
        AssertTrue(SegmentationGeometry.GetBounds(brushStroke[0]).Contains(new Point(18, 10)), "brush stroke polygon should cover the last stroke point");
        List<Point> eraseSource = SegmentationGeometry.RectangleToPolygon(new Rectangle(5, 5, 20, 12), new Size(40, 30));
        List<List<Point>> edgeErased = SegmentationGeometry.EraseCircleFromPolygon(eraseSource, new Point(23, 11), 5, new Size(40, 30));
        AssertEqual(1, edgeErased.Count);
        AssertTrue(!SegmentationGeometry.ContainsPoint(edgeErased[0], new Point(23, 11)), "edge eraser should remove the brush center from the segment");
        List<Point> splitSource = SegmentationGeometry.RectangleToPolygon(new Rectangle(2, 2, 30, 12), new Size(40, 30));
        List<List<Point>> splitErased = SegmentationGeometry.EraseCircleFromPolygon(splitSource, new Point(17, 8), 8, new Size(40, 30));
        AssertTrue(splitErased.Count >= 2, "eraser should split separated remaining mask components");
        List<Point> mergedHull = SegmentationGeometry.MergePolygonsToHull(
            new[]
            {
                SegmentationGeometry.RectangleToPolygon(new Rectangle(1, 1, 5, 5), new Size(30, 30)),
                SegmentationGeometry.RectangleToPolygon(new Rectangle(12, 8, 4, 4), new Size(30, 30))
            },
            new Size(30, 30));
        AssertTrue(mergedHull.Count >= 3, "merged segmentation hull should create an editable polygon");
        AssertTrue(SegmentationGeometry.GetBounds(mergedHull).Contains(new Point(12, 8)), "merged hull should include the second segment bounds");

        using var image = new Bitmap(40, 40);
        using (Graphics graphics = Graphics.FromImage(image))
        {
            graphics.Clear(Color.FromArgb(180, 180, 180));
            using var brushFill = new SolidBrush(Color.FromArgb(25, 25, 25));
            graphics.FillEllipse(brushFill, 14, 15, 9, 8);
        }

        List<Point> extracted = SegmentationGeometry.ExtractDarkRegionPolygon(image, new Rectangle(8, 8, 24, 24));
        Rectangle extractedBounds = SegmentationGeometry.GetBounds(extracted);
        AssertTrue(extracted.Count >= 3, "dark region extraction should create a polygon");
        AssertTrue(extractedBounds.Contains(new Point(18, 18)), "dark region extraction should include the defect center");
    }

    private static void TestWpfPolygonAnnotationService()
    {
        string root = CreateTempRoot();
        try
        {
            var data = new CData();
            data.ConfigureOutputRoot(root);
            data.ProjectSettings.YoloDataset.ValidationPercent = 0;
            var defectClass = new CClassItem { Text = "Defect", DrawColor = Color.Red };
            data.ClassNamedList.Add(defectClass);

            var service = new WpfPolygonAnnotationService();
            Size imageSize = new Size(20, 20);
            bool closed;

            AssertTrue(service.TryAddPoint(new Point(-4, 2), imageSize, out closed), "first polygon point was not accepted");
            AssertTrue(!closed, "polygon should not close after the first point");
            AssertEqual(new Point(0, 2), service.Points[0]);
            AssertTrue(service.TryAddPoint(new Point(12, 2), imageSize, out closed), "second polygon point was not accepted");
            AssertTrue(service.TryAddPoint(new Point(12, 12), imageSize, out closed), "third polygon point was not accepted");
            AssertTrue(service.TryAddPoint(new Point(2, 12), imageSize, out closed), "fourth polygon point was not accepted");
            AssertEqual(4, service.Points.Count);
            AssertTrue(service.TryAddPoint(new Point(1, 3), imageSize, out closed), "near-start click should close the polygon draft");
            AssertTrue(closed, "near-start click did not report closed polygon");
            AssertTrue(service.IsClosed, "polygon draft should stay closed after near-start click");
            AssertEqual(4, service.Points.Count);

            AssertTrue(service.TryComplete(defectClass, imageSize, out LabelingSegmentationObject annotation, out string message), message);
            AssertEqual("Defect", annotation.ClassName);
            AssertEqual(4, annotation.Points.Count);
            AssertEqual(new Rectangle(0, 2, 13, 11), annotation.Bounds);
            AssertTrue(SegmentationGeometry.ContainsPoint(annotation.Points, new Point(6, 6)), "completed WPF polygon should contain its center");
            AssertEqual(0, WpfPolygonAnnotationService.FindNearestPointIndex(annotation, new Point(0, 2), 5));
            AssertTrue(WpfPolygonAnnotationService.TryMovePoint(annotation, 0, new Point(4, 4), imageSize, out Rectangle polygonMoveBounds), "polygon point should move in image-pixel coordinates");
            AssertEqual(new Point(4, 4), annotation.Points[0]);
            AssertTrue(polygonMoveBounds.Contains(new Point(4, 4)), "polygon point move bounds should include the new point");

            AssertTrue(WpfPolygonAnnotationService.TryCreateObject(
                new[]
                {
                    new Point(3, 3),
                    new Point(3, 3),
                    new Point(3, 3)
                },
                defectClass,
                imageSize,
                out LabelingSegmentationObject invalid) == false, "degenerate polygon should not create an annotation object");
            AssertTrue(invalid == null, "invalid polygon should not return an annotation object");

            using var image = new Bitmap(imageSize.Width, imageSize.Height);
            YoloSegmentationAnnotationService.SaveSegmentationAnnotations(
                "wpf-polygon.png",
                image,
                new Dictionary<string, List<LabelingSegmentationObject>>
                {
                    ["Defect"] = new List<LabelingSegmentationObject> { annotation }
                },
                data.ClassNamedList,
                data);

            string segmentPath = Path.Combine(root, "data", "train", "segments", "wpf-polygon.json");
            AssertTrue(File.Exists(segmentPath), "WPF polygon segmentation json was not saved");
            IReadOnlyDictionary<string, List<LabelingSegmentationObject>> loaded = YoloSegmentationAnnotationService.LoadSegmentationObjects(
                segmentPath,
                data.ClassNamedList,
                imageSize);
            AssertEqual(1, loaded["Defect"].Count);
            AssertEqual(annotation.Bounds, loaded["Defect"][0].Bounds);
        }
        finally
        {
            DeleteTempRoot(root);
        }
    }

    private static void TestWpfPolygonShellInputCreatesSegmentation()
    {
        if (System.Windows.Application.Current == null)
        {
            _ = new System.Windows.Application
            {
                ShutdownMode = System.Windows.ShutdownMode.OnExplicitShutdown
            };
        }

        WpfLabelingShellWindow window = new WpfLabelingShellWindow();
        Bitmap bitmap = new Bitmap(40, 40);
        try
        {
            SetPrivateField(window, "activeImageSize", new Size(40, 40));
            SetPrivateField(window, "activeImageBitmap", bitmap);
            CGlobal.Inst.Data.LastSelectImageName = "wpf-polygon-shell";
            CGlobal.Inst.Data.ClassNamedList.Clear();
            CGlobal.Inst.Data.ClassNamedList.Add(new CClassItem { Text = "Defect", DrawColor = Color.DeepSkyBlue });

            InvokePrivateResult<object>(window, "BeginPolygonAnnotationMode");
            AssertTrue(window.MainCanvasViewModel.IsImagePointInputMode, "polygon tool should enter image-pixel click input mode");

            InvokePrivateResult<object>(window, "MainCanvasViewModel_ImagePointClicked", window.MainCanvasViewModel, new CanvasImagePointEventArgs(CanvasPointerButton.Left, 1, 0, 0, new Point(5, 5), PointF.Empty));
            AssertEqual(1, window.MainCanvasViewModel.PolygonOverlays.Count);
            AssertTrue(window.MainCanvasViewModel.PolygonOverlays[0].IsDraft, "first polygon click should render a draft overlay");

            InvokePrivateResult<object>(window, "MainCanvasViewModel_ImagePointClicked", window.MainCanvasViewModel, new CanvasImagePointEventArgs(CanvasPointerButton.Left, 1, 0, 0, new Point(25, 5), PointF.Empty));
            InvokePrivateResult<object>(window, "MainCanvasViewModel_ImagePointClicked", window.MainCanvasViewModel, new CanvasImagePointEventArgs(CanvasPointerButton.Left, 1, 0, 0, new Point(25, 20), PointF.Empty));
            InvokePrivateResult<object>(window, "MainCanvasViewModel_ImagePointClicked", window.MainCanvasViewModel, new CanvasImagePointEventArgs(CanvasPointerButton.Left, 1, 0, 0, new Point(6, 6), PointF.Empty));

            var manualSegments = GetPrivateField<List<LabelingSegmentationObject>>(window, "manualSegments");
            AssertEqual(1, manualSegments.Count);
            AssertEqual("Defect", manualSegments[0].ClassName);
            AssertTrue(SegmentationGeometry.ContainsPoint(manualSegments[0].Points, new Point(12, 9)), "completed shell polygon should contain an interior image point");
            AssertEqual(1, window.MainCanvasViewModel.PolygonOverlays.Count);
            AssertTrue(!window.MainCanvasViewModel.PolygonOverlays[0].IsDraft, "completed polygon should render as a confirmed overlay");

            Dictionary<string, List<LabelingSegmentationObject>> segmentsByClass = InvokePrivateResult<Dictionary<string, List<LabelingSegmentationObject>>>(window, "BuildAnnotationSegments");
            AssertEqual(1, segmentsByClass["Defect"].Count);
            var objectReviewPanel = (WpfObjectReviewPanel)window.FindName("ObjectReviewPanelControl");
            AssertTrue(objectReviewPanel.ViewModel.Objects.Any(item => item.DisplayText.Contains("\uD3F4\uB9AC\uACE4", StringComparison.Ordinal)), "object review should list the completed polygon with a user-facing label");

            SetPrivateField(window, "activeAnnotationTool", WpfAnnotationTool.Select);
            window.MainCanvasViewModel.IsImagePointInputMode = true;
            objectReviewPanel.ViewModel.SelectedObject = objectReviewPanel.ViewModel.Objects.First(item => item.DisplayText.Contains("\uD3F4\uB9AC\uACE4", StringComparison.Ordinal));
            Point originalPoint = manualSegments[0].Points[0];
            InvokePrivateResult<object>(window, "MainCanvasViewModel_ImagePointClicked", window.MainCanvasViewModel, new CanvasImagePointEventArgs(CanvasPointerButton.Left, 1, 0, 0, originalPoint, PointF.Empty));
            InvokePrivateResult<object>(window, "MainCanvasViewModel_ImagePointMoved", window.MainCanvasViewModel, new CanvasImagePointEventArgs(CanvasPointerButton.Left, 1, 0, 0, new Point(originalPoint.X + 3, originalPoint.Y + 2), PointF.Empty));
            InvokePrivateResult<object>(window, "MainCanvasViewModel_ImagePointReleased", window.MainCanvasViewModel, new CanvasImagePointEventArgs(CanvasPointerButton.Left, 1, 0, 0, new Point(originalPoint.X + 3, originalPoint.Y + 2), PointF.Empty));
            AssertEqual(new Point(originalPoint.X + 3, originalPoint.Y + 2), manualSegments[0].Points[0]);
        }
        finally
        {
            SetPrivateField(window, "activeImageBitmap", null);
            window.Close();
            bitmap.Dispose();
        }
    }

    private static void TestWpfMaskAnnotationService()
    {
        var service = new WpfMaskAnnotationService();
        var segments = new List<LabelingSegmentationObject>();
        Size imageSize = new Size(30, 30);
        var defectClass = new CClassItem { Text = "Defect", DrawColor = Color.DeepSkyBlue };

        AssertTrue(service.Paint(
            segments,
            new[] { new Point(10, 10) },
            3,
            imageSize,
            defectClass,
            out LabelingSegmentationObject paintedSegment,
            out Rectangle firstBounds), "brush should paint a raster mask");
        AssertEqual(1, segments.Count);
        AssertTrue(paintedSegment.IsRasterMask, "brush should create a raster mask segment");
        AssertEqual(imageSize, paintedSegment.MaskSize);
        AssertTrue(firstBounds.Contains(new Point(10, 10)), "changed bounds should include the brush center");
        AssertTrue(paintedSegment.Bounds.Contains(new Point(10, 10)), "mask bounds should include the brush center");
        AssertTrue(paintedSegment.MaskData[(10 * imageSize.Width) + 10] > 0, "brush center pixel should be painted");

        IReadOnlyList<Point> stroke = service.BuildStrokeCenters(new Point(10, 10), new Point(18, 10), 3);
        AssertTrue(stroke.Count > 2, "drag stroke should interpolate centers between sparse mouse events");
        AssertTrue(service.Paint(
            segments,
            stroke,
            3,
            imageSize,
            defectClass,
            out LabelingSegmentationObject strokeSegment,
            out _), "interpolated stroke should update the mask");
        AssertTrue(ReferenceEquals(paintedSegment, strokeSegment), "same class brush strokes should reuse the raster mask segment");
        AssertTrue(strokeSegment.Bounds.Contains(new Point(18, 10)), "stroke end should be included in mask bounds");
        Rectangle beforeMoveBounds = strokeSegment.Bounds;
        int renderVersionBeforeMove = strokeSegment.RenderVersion;
        AssertTrue(service.TryMoveRasterMask(strokeSegment, 2, 3, imageSize, out Rectangle moveBounds), "selected raster mask should move in image-pixel coordinates");
        AssertEqual(new Rectangle(beforeMoveBounds.X + 2, beforeMoveBounds.Y + 3, beforeMoveBounds.Width, beforeMoveBounds.Height), strokeSegment.Bounds);
        AssertTrue(strokeSegment.RenderVersion > renderVersionBeforeMove, "mask move should invalidate the OpenGL texture preview");
        AssertTrue(moveBounds.Contains(new Point(beforeMoveBounds.Left, beforeMoveBounds.Top)), "mask move dirty bounds should include the old mask area");
        AssertTrue(strokeSegment.MaskData[(13 * imageSize.Width) + 12] > 0, "mask move should carry painted pixels to the new location");

        AssertTrue(service.Erase(
            segments,
            new[] { new Point(12, 13) },
            3,
            imageSize,
            out Rectangle eraseBounds), "eraser should modify an existing raster mask");
        AssertTrue(eraseBounds.Contains(new Point(12, 13)), "erase bounds should include the erased center");
        AssertEqual((byte)0, paintedSegment.MaskData[(13 * imageSize.Width) + 12]);

        AssertTrue(service.Erase(
            segments,
            new[] { new Point(17, 13) },
            20,
            imageSize,
            out _), "large eraser should clear the remaining mask");
        AssertEqual(0, segments.Count);

        var performanceSegments = new List<LabelingSegmentationObject>();
        var performanceImageSize = new Size(2_048, 2_048);
        var performanceCenters = new List<Point>(2_000);
        for (int index = 0; index < 2_000; index++)
        {
            performanceCenters.Add(new Point(
                96 + (index % 640),
                96 + ((index / 640) * 48)));
        }

        long allocatedBefore = GC.GetAllocatedBytesForCurrentThread();
        Stopwatch stopwatch = Stopwatch.StartNew();
        AssertTrue(service.Paint(
            performanceSegments,
            performanceCenters,
            18,
            performanceImageSize,
            defectClass,
            out LabelingSegmentationObject performanceSegment,
            out Rectangle performanceBounds), "long brush stroke should commit to the CPU mask");
        stopwatch.Stop();
        long allocatedBytes = GC.GetAllocatedBytesForCurrentThread() - allocatedBefore;
        Console.WriteLine(
            string.Create(
                CultureInfo.InvariantCulture,
                $"WPF_MASK_STAMP_COMMIT_2000_CENTERS_MS={stopwatch.Elapsed.TotalMilliseconds:F3} ALLOCATED_MB={allocatedBytes / (1024D * 1024D):F3} BOUNDS={performanceBounds}"));

        AssertEqual(1, performanceSegments.Count);
        AssertTrue(performanceSegment.Bounds.Contains(new Point(96, 96)), "long brush stroke should include the first center");
        AssertTrue(performanceSegment.Bounds.Contains(performanceCenters[performanceCenters.Count - 1]), "long brush stroke should include the last center");
        AssertTrue(stopwatch.Elapsed.TotalMilliseconds < 150.0, "mask brush MouseUp commit should use cached row spans instead of per-pixel double circle tests");

        var edgeEraseImageSize = new Size(2_048, 2_048);
        var edgeEraseBounds = new Rectangle(256, 256, 1_536, 1_536);
        var edgeEraseSegment = new LabelingSegmentationObject(Array.Empty<Point>(), defectClass)
        {
            ClassName = "Defect",
            ClassItem = defectClass,
            MaskData = new byte[edgeEraseImageSize.Width * edgeEraseImageSize.Height],
            MaskSize = edgeEraseImageSize,
            MaskBounds = edgeEraseBounds,
            RenderVersion = 1,
            RenderDirtyBounds = Rectangle.Empty
        };
        for (int y = edgeEraseBounds.Top; y < edgeEraseBounds.Bottom; y++)
        {
            int rowOffset = y * edgeEraseImageSize.Width;
            for (int x = edgeEraseBounds.Left; x < edgeEraseBounds.Right; x++)
            {
                edgeEraseSegment.MaskData[rowOffset + x] = 1;
            }
        }

        var edgeEraseSegments = new List<LabelingSegmentationObject> { edgeEraseSegment };
        var edgeEraseCenters = new List<Point>();
        for (int y = edgeEraseBounds.Top; y < edgeEraseBounds.Bottom; y += 8)
        {
            edgeEraseCenters.Add(new Point(edgeEraseBounds.Left, y));
        }

        long edgeEraseAllocatedBefore = GC.GetAllocatedBytesForCurrentThread();
        Stopwatch edgeEraseStopwatch = Stopwatch.StartNew();
        AssertTrue(service.Erase(
            edgeEraseSegments,
            edgeEraseCenters,
            8,
            edgeEraseImageSize,
            out Rectangle edgeEraseChangedBounds), "edge eraser should update a large raster mask");
        edgeEraseStopwatch.Stop();
        long edgeEraseAllocatedBytes = GC.GetAllocatedBytesForCurrentThread() - edgeEraseAllocatedBefore;
        Console.WriteLine(
            string.Create(
                CultureInfo.InvariantCulture,
                $"WPF_MASK_EDGE_ERASE_2048_MS={edgeEraseStopwatch.Elapsed.TotalMilliseconds:F3} ALLOCATED_MB={edgeEraseAllocatedBytes / (1024D * 1024D):F3} OLD_BOUNDS={edgeEraseBounds} NEW_BOUNDS={edgeEraseSegment.Bounds} CHANGED={edgeEraseChangedBounds}"));

        AssertTrue(edgeEraseSegment.Bounds.Left > edgeEraseBounds.Left, "edge eraser should shrink the active mask left bound");
        AssertEqual(edgeEraseBounds.Top, edgeEraseSegment.Bounds.Top);
        AssertEqual(edgeEraseBounds.Bottom, edgeEraseSegment.Bounds.Bottom);
        AssertTrue(edgeEraseStopwatch.Elapsed.TotalMilliseconds < 120.0, "edge eraser should shrink bounds by scanning touched edges instead of the full active mask");
    }

    private static void TestWpfMaskOverlayDirtyBoundsResetAfterUpload()
    {
        var dirtyBounds = new Rectangle(2, 3, 7, 8);
        int uploadedVersion = -1;
        Rectangle uploadedBounds = Rectangle.Empty;
        int callbackCount = 0;
        var overlay = new RoiImageCanvasMaskOverlay(
            "mask-dirty-reset",
            new byte[10 * 10],
            new Size(10, 10),
            new Rectangle(0, 0, 10, 10),
            Color.DeepSkyBlue,
            0.66F,
            5,
            false,
            "MASK",
            dirtyBounds,
            (version, bounds) =>
            {
                callbackCount++;
                uploadedVersion = version;
                uploadedBounds = bounds;
            });

        overlay.NotifyDirtyBoundsUploaded();
        AssertEqual(1, callbackCount);
        AssertEqual(5, uploadedVersion);
        AssertEqual(dirtyBounds, uploadedBounds);

        var defectClass = new CClassItem { Text = "Defect", DrawColor = Color.DeepSkyBlue };
        var segment = new LabelingSegmentationObject(Array.Empty<Point>(), defectClass)
        {
            ClassName = "Defect",
            ClassItem = defectClass,
            MaskData = new byte[10 * 10],
            MaskSize = new Size(10, 10),
            MaskBounds = new Rectangle(0, 0, 10, 10),
            RenderVersion = 5,
            RenderDirtyBounds = dirtyBounds
        };

        InvokePrivateStaticResult<object>(typeof(WpfLabelingShellWindow), "ClearMaskRenderDirtyBounds", segment, 4, dirtyBounds);
        AssertEqual(dirtyBounds, segment.RenderDirtyBounds);

        InvokePrivateStaticResult<object>(typeof(WpfLabelingShellWindow), "ClearMaskRenderDirtyBounds", segment, 5, dirtyBounds);
        AssertEqual(Rectangle.Empty, segment.RenderDirtyBounds);

        segment.RenderVersion = 6;
        segment.RenderDirtyBounds = dirtyBounds;
        InvokePrivateStaticResult<object>(typeof(WpfLabelingShellWindow), "ClearMaskRenderDirtyBounds", segment, 5, dirtyBounds);
        AssertEqual(dirtyBounds, segment.RenderDirtyBounds);
    }
    private static void TestWpfRasterMaskMoveAvoidsFullImageAllocation()
    {
        var service = new WpfMaskAnnotationService();
        var imageSize = new Size(4_096, 4_096);
        var defectClass = new CClassItem { Text = "Defect", DrawColor = Color.DeepSkyBlue };
        var maskBounds = new Rectangle(200, 200, 64, 64);
        var segment = new LabelingSegmentationObject(Array.Empty<Point>(), defectClass)
        {
            ClassName = "Defect",
            ClassItem = defectClass,
            MaskData = new byte[imageSize.Width * imageSize.Height],
            MaskSize = imageSize,
            MaskBounds = maskBounds,
            RenderVersion = 1,
            RenderDirtyBounds = Rectangle.Empty
        };

        for (int y = maskBounds.Top; y < maskBounds.Bottom; y++)
        {
            int rowOffset = y * imageSize.Width;
            for (int x = maskBounds.Left; x < maskBounds.Right; x++)
            {
                segment.MaskData[rowOffset + x] = 1;
            }
        }

        byte[] originalMaskData = segment.MaskData;
        long allocatedBefore = GC.GetAllocatedBytesForCurrentThread();
        Stopwatch stopwatch = Stopwatch.StartNew();
        for (int index = 0; index < 1_000; index++)
        {
            int deltaX = index % 2 == 0 ? 1 : -1;
            AssertTrue(service.TryMoveRasterMask(segment, deltaX, 0, imageSize, out _), "large image mask move should stay editable");
        }

        stopwatch.Stop();
        long allocatedBytes = GC.GetAllocatedBytesForCurrentThread() - allocatedBefore;
        Console.WriteLine(
            string.Create(
                CultureInfo.InvariantCulture,
                $"WPF_RASTER_MASK_MOVE_4096_1000_MS={stopwatch.Elapsed.TotalMilliseconds:F3} ALLOCATED_MB={allocatedBytes / (1024D * 1024D):F3} SAME_BUFFER={ReferenceEquals(originalMaskData, segment.MaskData)} BOUNDS={segment.Bounds}"));

        AssertTrue(ReferenceEquals(originalMaskData, segment.MaskData), "raster mask move should reuse the full image buffer instead of allocating one per MouseMove");
        AssertEqual(maskBounds, segment.Bounds);
        AssertTrue(segment.MaskData[(maskBounds.Top * imageSize.Width) + maskBounds.Left] > 0, "raster mask move should preserve painted pixels");
        AssertTrue(allocatedBytes < 64L * 1024L * 1024L, "raster mask move should allocate only the active bounds buffer, not the full image mask per move");
        AssertTrue(stopwatch.Elapsed.TotalMilliseconds < 500.0, "raster mask move should stay lightweight for large images when the active mask bounds are small");

        var largeActiveImageSize = new Size(2_048, 2_048);
        var largeActiveBounds = new Rectangle(256, 256, 1_536, 1_536);
        var largeActiveSegment = new LabelingSegmentationObject(Array.Empty<Point>(), defectClass)
        {
            ClassName = "Defect",
            ClassItem = defectClass,
            MaskData = new byte[largeActiveImageSize.Width * largeActiveImageSize.Height],
            MaskSize = largeActiveImageSize,
            MaskBounds = largeActiveBounds,
            RenderVersion = 1,
            RenderDirtyBounds = Rectangle.Empty
        };

        for (int y = largeActiveBounds.Top; y < largeActiveBounds.Bottom; y++)
        {
            int rowOffset = y * largeActiveImageSize.Width;
            for (int x = largeActiveBounds.Left; x < largeActiveBounds.Right; x++)
            {
                largeActiveSegment.MaskData[rowOffset + x] = 1;
            }
        }

        byte[] originalLargeMaskData = largeActiveSegment.MaskData;
        long largeAllocatedBefore = GC.GetAllocatedBytesForCurrentThread();
        Stopwatch largeStopwatch = Stopwatch.StartNew();
        for (int index = 0; index < 100; index++)
        {
            int deltaX = index % 2 == 0 ? 1 : -1;
            AssertTrue(service.TryMoveRasterMask(largeActiveSegment, deltaX, 0, largeActiveImageSize, out _), "large active mask move should stay editable");
        }

        largeStopwatch.Stop();
        long largeAllocatedBytes = GC.GetAllocatedBytesForCurrentThread() - largeAllocatedBefore;
        Console.WriteLine(
            string.Create(
                CultureInfo.InvariantCulture,
                $"WPF_RASTER_MASK_LARGE_ACTIVE_MOVE_2048_100_MS={largeStopwatch.Elapsed.TotalMilliseconds:F3} ALLOCATED_MB={largeAllocatedBytes / (1024D * 1024D):F3} SAME_BUFFER={ReferenceEquals(originalLargeMaskData, largeActiveSegment.MaskData)} BOUNDS={largeActiveSegment.Bounds}"));

        AssertTrue(ReferenceEquals(originalLargeMaskData, largeActiveSegment.MaskData), "large active mask move should keep the original full image mask buffer");
        AssertEqual(largeActiveBounds, largeActiveSegment.Bounds);
        AssertTrue(largeAllocatedBytes < 64L * 1024L * 1024L, "large active mask move should rent scratch memory instead of allocating one multi-MB array per MouseMove");
        AssertTrue(largeStopwatch.Elapsed.TotalMilliseconds < 750.0, "large active mask move should remain bounded even when the active mask covers much of the image");
    }

    private static void TestWpfBrushEraserShellInputCreatesMaskSegmentation()
    {
        if (System.Windows.Application.Current == null)
        {
            _ = new System.Windows.Application
            {
                ShutdownMode = System.Windows.ShutdownMode.OnExplicitShutdown
            };
        }

        CData previousData = CGlobal.Inst.Data;
        var data = new CData();
        data.LastSelectImageName = "wpf-mask-shell";
        data.ClassNamedList.Add(new CClassItem { Text = "Defect", DrawColor = Color.LimeGreen });
        CGlobal.Inst.Data = data;

        WpfLabelingShellWindow window = new WpfLabelingShellWindow();
        Bitmap bitmap = new Bitmap(40, 40);
        try
        {
            SetPrivateField(window, "activeImageSize", new Size(40, 40));
            SetPrivateField(window, "activeImageBitmap", bitmap);
            SetPrivateField(window.MainCanvasViewModel, "_imageSize", new Size(40, 40));

            InvokePrivateResult<object>(window, "BeginMaskAnnotationMode", WpfAnnotationTool.Brush);
            AssertTrue(window.MainCanvasViewModel.IsImagePointInputMode, "brush tool should enter image-pixel mask input mode");
            AssertTrue(!window.MainCanvasViewModel.IsTeachingMode, "brush tool should not use ROI drawing mode");
            InvokePrivateResult<object>(window, "MainCanvasViewModel_ImagePointHovered", window.MainCanvasViewModel, new CanvasImagePointEventArgs(CanvasPointerButton.None, 0, 0, 0, new Point(10, 10), PointF.Empty));
            AssertTrue(window.MainCanvasViewModel.IsBrushCursorPreviewVisible, "brush hover should show the image-pixel radius preview");
            AssertEqual(6, window.MainCanvasViewModel.BrushCursorPreviewRadius);

            InvokePrivateResult<object>(window, "MainCanvasViewModel_ImagePointClicked", window.MainCanvasViewModel, new CanvasImagePointEventArgs(CanvasPointerButton.Left, 1, 0, 0, new Point(10, 10), PointF.Empty));
            InvokePrivateResult<object>(window, "MainCanvasViewModel_ImagePointMoved", window.MainCanvasViewModel, new CanvasImagePointEventArgs(CanvasPointerButton.Left, 1, 0, 0, new Point(18, 10), PointF.Empty));
            InvokePrivateResult<object>(window, "MainCanvasViewModel_ImagePointReleased", window.MainCanvasViewModel, new CanvasImagePointEventArgs(CanvasPointerButton.Left, 1, 0, 0, new Point(18, 10), PointF.Empty));
            PumpWpfDispatcher(TimeSpan.FromMilliseconds(430));
            System.Windows.Threading.Dispatcher.CurrentDispatcher.Invoke(
                new Action(() => { }),
                System.Windows.Threading.DispatcherPriority.ApplicationIdle);

            var manualSegments = GetPrivateField<List<LabelingSegmentationObject>>(window, "manualSegments");
            AssertEqual(0, manualSegments.Count);
            AssertTrue(window.MainCanvasViewModel.IsMaskStrokePreviewVisible, "brush MouseUp should keep the GPU preview while the brush tool remains active");
            InvokePrivateResult<object>(window, "EndMaskAnnotationMode");
            PumpWpfDispatcher(TimeSpan.FromMilliseconds(260));
            System.Windows.Threading.Dispatcher.CurrentDispatcher.Invoke(
                new Action(() => { }),
                System.Windows.Threading.DispatcherPriority.ApplicationIdle);

            AssertEqual(1, manualSegments.Count);
            LabelingSegmentationObject maskSegment = manualSegments[0];
            AssertTrue(maskSegment.IsRasterMask, "WPF brush should create a raster mask segment");
            AssertEqual("Defect", maskSegment.ClassName);
            AssertTrue(maskSegment.MaskData[(10 * 40) + 10] > 0, "WPF brush should paint the clicked image pixel");
            AssertEqual(1, window.MainCanvasViewModel.MaskOverlays.Count);
            AssertEqual(0, window.MainCanvasViewModel.PolygonOverlays.Count);
            AssertTrue(window.MainCanvasViewModel.MaskOverlays[0].IsValid, "raster mask should render through the OpenGL texture overlay preview");
            AssertTrue(!window.MainCanvasViewModel.MaskOverlays[0].IsSelected, "brush painting should not pop a selected MASK label over the active canvas");
            AssertTrue(window.MainCanvasViewModel.MaskOverlays[0].Label.Contains("MASK", StringComparison.Ordinal), "mask overlay should carry a compact canvas selection label");

            Dictionary<string, List<LabelingSegmentationObject>> segmentsByClass = InvokePrivateResult<Dictionary<string, List<LabelingSegmentationObject>>>(window, "BuildAnnotationSegments");
            AssertEqual(1, segmentsByClass["Defect"].Count);
            AssertTrue(segmentsByClass["Defect"][0].IsRasterMask, "WPF save path should keep raster mask segments");

            var objectReviewPanel = (WpfObjectReviewPanel)window.FindName("ObjectReviewPanelControl");
            AssertTrue(objectReviewPanel.ViewModel.Objects.Any(item => item.DisplayText.Contains("\uB9C8\uC2A4\uD06C", StringComparison.Ordinal)), "object review should list the mask with a user-facing label");
            objectReviewPanel.ViewModel.SelectedObject = objectReviewPanel.ViewModel.Objects.First(item => item.DisplayText.Contains("\uB9C8\uC2A4\uD06C", StringComparison.Ordinal));

            SetPrivateField(window, "activeAnnotationTool", WpfAnnotationTool.Select);
            window.MainCanvasViewModel.IsImagePointInputMode = true;
            Rectangle maskBoundsBeforeMove = maskSegment.Bounds;
            InvokePrivateResult<object>(window, "MainCanvasViewModel_ImagePointClicked", window.MainCanvasViewModel, new CanvasImagePointEventArgs(CanvasPointerButton.Left, 1, 0, 0, new Point(18, 10), PointF.Empty));
            InvokePrivateResult<object>(window, "MainCanvasViewModel_ImagePointMoved", window.MainCanvasViewModel, new CanvasImagePointEventArgs(CanvasPointerButton.Left, 1, 0, 0, new Point(21, 12), PointF.Empty));
            InvokePrivateResult<object>(window, "MainCanvasViewModel_ImagePointReleased", window.MainCanvasViewModel, new CanvasImagePointEventArgs(CanvasPointerButton.Left, 1, 0, 0, new Point(21, 12), PointF.Empty));
            AssertEqual(new Rectangle(maskBoundsBeforeMove.X + 3, maskBoundsBeforeMove.Y + 2, maskBoundsBeforeMove.Width, maskBoundsBeforeMove.Height), maskSegment.Bounds);

            InvokePrivateResult<object>(window, "BeginMaskAnnotationMode", WpfAnnotationTool.Eraser);
            InvokePrivateResult<object>(window, "MainCanvasViewModel_ImagePointHovered", window.MainCanvasViewModel, new CanvasImagePointEventArgs(CanvasPointerButton.None, 0, 0, 0, new Point(10, 10), PointF.Empty));
            AssertTrue(window.MainCanvasViewModel.IsBrushCursorPreviewVisible, "eraser hover should keep the radius preview visible");
            InvokePrivateResult<object>(window, "MainCanvasViewModel_ImagePointClicked", window.MainCanvasViewModel, new CanvasImagePointEventArgs(CanvasPointerButton.Left, 1, 0, 0, new Point(13, 12), PointF.Empty));
            InvokePrivateResult<object>(window, "MainCanvasViewModel_ImagePointReleased", window.MainCanvasViewModel, new CanvasImagePointEventArgs(CanvasPointerButton.Left, 1, 0, 0, new Point(13, 12), PointF.Empty));
            PumpWpfDispatcher(TimeSpan.FromMilliseconds(430));
            System.Windows.Threading.Dispatcher.CurrentDispatcher.Invoke(
                new Action(() => { }),
                System.Windows.Threading.DispatcherPriority.ApplicationIdle);
            InvokePrivateResult<object>(window, "EndMaskAnnotationMode");
            PumpWpfDispatcher(TimeSpan.FromMilliseconds(260));
            System.Windows.Threading.Dispatcher.CurrentDispatcher.Invoke(
                new Action(() => { }),
                System.Windows.Threading.DispatcherPriority.ApplicationIdle);
            AssertEqual((byte)0, maskSegment.MaskData[(12 * 40) + 13]);
            AssertTrue(window.MainCanvasViewModel.MaskOverlays.Count <= 1, "mask overlay refresh should not duplicate stale texture overlays");
            AssertTrue(!window.MainCanvasViewModel.IsBrushCursorPreviewVisible, "mask cursor preview should clear when the mask tool ends");
        }
        finally
        {
            SetPrivateField(window, "activeImageBitmap", null);
            window.Close();
            bitmap.Dispose();
            CGlobal.Inst.Data = previousData;
        }
    }

    private static void TestWpfDatasetPurposeHidesSegmentationAnnotations()
    {
        if (System.Windows.Application.Current == null)
        {
            _ = new System.Windows.Application
            {
                ShutdownMode = System.Windows.ShutdownMode.OnExplicitShutdown
            };
        }

        CData previousData = CGlobal.Inst.Data;
        var data = new CData();
        data.LastSelectImageName = "wpf-annotation-purpose-scope";
        data.ProjectSettings.DatasetPurpose = LabelingDatasetPurpose.Segmentation;
        var defectClass = new CClassItem { Text = "Defect", DrawColor = Color.LimeGreen };
        data.ClassNamedList.Add(defectClass);
        CGlobal.Inst.Data = data;

        WpfLabelingShellWindow window = new WpfLabelingShellWindow();
        Bitmap bitmap = new Bitmap(80, 80);
        try
        {
            SetPrivateField(window, "activeImageSize", new Size(80, 80));
            SetPrivateField(window, "activeImageBitmap", bitmap);
            SetPrivateField(window.MainCanvasViewModel, "_imageSize", new Size(80, 80));

            var manualSegments = GetPrivateField<List<LabelingSegmentationObject>>(window, "manualSegments");
            manualSegments.Add(new LabelingSegmentationObject(
                new[]
                {
                    new Point(10, 10),
                    new Point(40, 10),
                    new Point(40, 30)
                },
                defectClass)
            {
                ClassName = "Defect",
                ClassItem = defectClass
            });

            InvokePrivateResult<object>(window, "RefreshPolygonOverlays");
            InvokePrivateResult<object>(window, "RefreshObjectList");
            var objectReviewPanel = (WpfObjectReviewPanel)window.FindName("ObjectReviewPanelControl");
            AssertEqual(1, window.MainCanvasViewModel.PolygonOverlays.Count);
            AssertTrue(objectReviewPanel.ViewModel.Objects.Any(item => item.DisplayText.Contains("\uD3F4\uB9AC\uACE4", StringComparison.Ordinal)), "segmentation purpose should show polygon rows");

            InvokePrivateResult<object>(window, "ApplyDatasetPurposeToCurrentProject", LabelingDatasetPurpose.ObjectDetection);
            InvokePrivateResult<object>(window, "RefreshAnnotationVisibilityForDatasetPurpose", true);

            AssertEqual(1, manualSegments.Count);
            AssertEqual(0, window.MainCanvasViewModel.PolygonOverlays.Count);
            AssertEqual(0, window.MainCanvasViewModel.MaskOverlays.Count);
            AssertTrue(!objectReviewPanel.ViewModel.Objects.Any(item => item.DisplayText.Contains("\uD3F4\uB9AC\uACE4", StringComparison.Ordinal)), "object-detection purpose should hide stale segmentation rows");
            AssertTrue(window.StatusBarViewModel.ModelStatusText.Contains("세그 라벨 1개 숨김", StringComparison.Ordinal), "purpose switch should tell the operator that segmentation labels were hidden, not deleted");

            Dictionary<string, List<LabelingSegmentationObject>> segmentsByClass = InvokePrivateResult<Dictionary<string, List<LabelingSegmentationObject>>>(window, "BuildAnnotationSegments");
            AssertEqual(0, segmentsByClass.Values.Sum(list => list.Count));

            InvokePrivateResult<object>(window, "ApplyDatasetPurposeToCurrentProject", LabelingDatasetPurpose.Segmentation);
            InvokePrivateResult<object>(window, "RefreshAnnotationVisibilityForDatasetPurpose", true);
            AssertEqual(1, window.MainCanvasViewModel.PolygonOverlays.Count);
            AssertTrue(window.StatusBarViewModel.ModelStatusText.Contains("세그 라벨 1개 표시", StringComparison.Ordinal), "purpose switch back to segmentation should report restored segmentation visibility");
        }
        finally
        {
            SetPrivateField(window, "activeImageBitmap", null);
            window.Close();
            bitmap.Dispose();
            CGlobal.Inst.Data = previousData;
        }
    }

    private static void TestWpfDatasetPurposeControlsSegmentationExportPolicy()
    {
        if (System.Windows.Application.Current == null)
        {
            _ = new System.Windows.Application
            {
                ShutdownMode = System.Windows.ShutdownMode.OnExplicitShutdown
            };
        }

        CData previousData = CGlobal.Inst.Data;
        string root = CreateTempRoot();
        var data = new CData();
        data.ConfigureOutputRoot(root);
        data.LastSelectImageName = "purpose-export.png";
        data.ProjectSettings.DatasetPurpose = LabelingDatasetPurpose.Segmentation;
        data.ProjectSettings.YoloDataset.ValidationPercent = 0;
        data.ProjectSettings.YoloDataset.TestPercent = 0;
        var defectClass = new CClassItem { Text = "Defect", DrawColor = Color.LimeGreen };
        data.ClassNamedList.Add(defectClass);
        CGlobal.Inst.Data = data;

        WpfLabelingShellWindow window = new WpfLabelingShellWindow();
        Bitmap bitmap = new Bitmap(80, 80);
        try
        {
            SetPrivateField(window, "activeImageSize", new Size(80, 80));
            SetPrivateField(window, "activeImageBitmap", bitmap);
            SetPrivateField(window.MainCanvasViewModel, "_imageSize", new Size(80, 80));

            var manualRois = GetPrivateField<List<Rectangle>>(window, "manualRois");
            var manualRoiClassNames = GetPrivateField<List<string>>(window, "manualRoiClassNames");
            var manualRoiShapeKinds = GetPrivateField<List<CanvasRoiShapeKind>>(window, "manualRoiShapeKinds");
            var manualRoiOverlayIds = GetPrivateField<List<string>>(window, "manualRoiOverlayIds");
            manualRois.Add(new Rectangle(8, 9, 20, 18));
            manualRoiClassNames.Add("Defect");
            manualRoiShapeKinds.Add(CanvasRoiShapeKind.Rectangle);
            manualRoiOverlayIds.Add("purpose-export-roi");

            var manualSegments = GetPrivateField<List<LabelingSegmentationObject>>(window, "manualSegments");
            manualSegments.Add(new LabelingSegmentationObject(
                new[]
                {
                    new Point(10, 10),
                    new Point(45, 10),
                    new Point(45, 35),
                    new Point(10, 35)
                },
                defectClass)
            {
                ClassName = "Defect",
                ClassItem = defectClass
            });

            string labelPath = Path.Combine(root, "data", "train", "labels", "purpose-export.txt");
            string maskPath = Path.Combine(root, "data", "train", "masks", "purpose-export.png");
            string segmentPath = Path.Combine(root, "data", "train", "segments", "purpose-export.json");
            Directory.CreateDirectory(Path.GetDirectoryName(maskPath));
            Directory.CreateDirectory(Path.GetDirectoryName(segmentPath));
            File.WriteAllText(maskPath, "stale mask");
            File.WriteAllText(segmentPath, "stale segment");

            InvokePrivateResult<object>(window, "ApplyDatasetPurposeToCurrentProject", LabelingDatasetPurpose.ObjectDetection);
            InvokePrivateResult<object>(window, "RefreshAnnotationVisibilityForDatasetPurpose", true);
            object[] objectSaveArgs = { 0 };
            AssertTrue(InvokePrivateResult<bool>(window, "SaveCurrentAnnotations", objectSaveArgs), "object-detection save should still write visible box labels");
            AssertEqual(1, (int)objectSaveArgs[0]);
            AssertTrue(File.Exists(labelPath), "object-detection save should write the YOLO box label");
            AssertTrue(!File.Exists(maskPath), "object-detection save should delete stale mask artifacts for this image");
            AssertTrue(!File.Exists(segmentPath), "object-detection save should delete stale segment artifacts for this image");

            InvokePrivateResult<object>(window, "ApplyDatasetPurposeToCurrentProject", LabelingDatasetPurpose.Segmentation);
            InvokePrivateResult<object>(window, "RefreshAnnotationVisibilityForDatasetPurpose", true);
            object[] segmentationSaveArgs = { 0 };
            AssertTrue(InvokePrivateResult<bool>(window, "SaveCurrentAnnotations", segmentationSaveArgs), "segmentation save should include visible segmentation labels");
            AssertEqual(2, (int)segmentationSaveArgs[0]);
            AssertTrue(File.Exists(maskPath), "segmentation save should write the mask artifact");
            AssertTrue(File.Exists(segmentPath), "segmentation save should write the polygon artifact");

            SegmentationAnnotationFile annotationFile = JsonConvert.DeserializeObject<SegmentationAnnotationFile>(File.ReadAllText(segmentPath));
            AssertTrue(annotationFile?.Polygons?.Count > 0, "segmentation export should contain polygon records after purpose restore");
        }
        finally
        {
            SetPrivateField(window, "activeImageBitmap", null);
            window.Close();
            bitmap.Dispose();
            CGlobal.Inst.Data = previousData;
            DeleteTempRoot(root);
        }
    }

