    private static void TestWpfDetectionWorkerCompletionWaiter()
    {
        string root = CreateTempRoot();
        try
        {
            string targetImagePath = Path.Combine(root, "target.bmp");
            string otherImagePath = Path.Combine(root, "other.bmp");
            var service = new DetectionResultApplicationService();
            using var waiter = new WpfDetectionWorkerCompletionWaiter(
                service,
                targetImagePath,
                CancellationToken.None);

            var otherData = new CData
            {
                LastSelectImageName = Path.GetFileNameWithoutExtension(otherImagePath),
                LastSelectImagePath = otherImagePath
            };
            service.RegisterPendingDetectionImage(otherData, new Size(10, 10));
            service.ApplyToDetectLayer(Array.Empty<DefectInfo>());
            AssertTrue(!waiter.Completion.IsCompleted, "worker waiter should ignore completed events for another image");

            var targetData = new CData
            {
                LastSelectImageName = Path.GetFileNameWithoutExtension(targetImagePath),
                LastSelectImagePath = targetImagePath
            };
            service.RegisterPendingDetectionImage(targetData, new Size(10, 10));
            AssertTrue(!waiter.Completion.IsCompleted, "worker waiter should ignore RequestStarted events for the target image");
            service.ApplyToDetectLayer(Array.Empty<DefectInfo>());

            AssertTrue(WaitUntil(() => waiter.Completion.IsCompleted, TimeSpan.FromSeconds(1)), "worker waiter did not complete for the target image");
            AssertEqual(DetectionCandidateUpdateReason.ResultCompleted, waiter.Completion.Result.Reason);
            AssertTrue(
                WpfDetectionWorkerCompletionWaiter.IsCompletionForImage(
                    new DetectionCandidatesUpdatedEventArgs(
                        Path.GetFileNameWithoutExtension(targetImagePath),
                        string.Empty,
                        0,
                        DetectionCandidateUpdateReason.ResultCompleted),
                    targetImagePath),
                "worker waiter should match path-only requests by image name when the event path is empty");
            AssertTrue(
                !WpfDetectionWorkerCompletionWaiter.IsCompletionForImage(
                    new DetectionCandidatesUpdatedEventArgs(
                        Path.GetFileNameWithoutExtension(targetImagePath),
                        targetImagePath,
                        0,
                        DetectionCandidateUpdateReason.RequestStarted),
                    targetImagePath),
                "worker waiter should not complete on request-start events");
        }
        finally
        {
            DeleteTempRoot(root);
        }
    }

    private static void TestYoloPythonClientStartInfo()
    {
        string root = CreateTempRoot();
        try
        {
            string scriptPath = Path.Combine(root, "labelling_tcp_client.py");
            string weightsPath = Path.Combine(root, "best.pt");
            string modelRootPath = Path.Combine(root, "yolov5Master");
            File.WriteAllText(scriptPath, "print('ready')");
            Directory.CreateDirectory(modelRootPath);

            var settings = new PythonModelSettings
            {
                ProjectRootPath = root,
                ClientScriptPath = scriptPath,
                WeightsPath = weightsPath,
                ImageRootPath = root,
                InferenceImageSize = 320,
                MinimumDetectionConfidence = 0.15F
            };

            AssertTrue(YoloPythonClientProcessService.TryCreateStartInfo(settings, out var startInfo, out string error), error);
            AssertEqual(root, startInfo.WorkingDirectory);
            AssertTrue(startInfo.CreateNoWindow, "Python client should start without opening a console window");
            AssertTrue(startInfo.ArgumentList.Contains(scriptPath), "client script was not passed to Python");
            AssertTrue(startInfo.ArgumentList.Contains("--retry"), "retry flag was not passed to Python");
            AssertTrue(startInfo.ArgumentList.Contains("--preload"), "preload flag should move model load into worker startup instead of the first image request");
            AssertTrue(startInfo.ArgumentList.Contains(weightsPath), "weights path was not passed to Python");
            AssertArgumentValue(startInfo.ArgumentList, "--model-root", modelRootPath);
            AssertArgumentValue(startInfo.ArgumentList, "--image-root", root);
            AssertArgumentValue(startInfo.ArgumentList, "--conf", "0.15");
            AssertArgumentValue(startInfo.ArgumentList, "--img-size", "320");

            AssertTrue(YoloPythonClientProcessService.TryCreateStartSignature(settings, out string firstSignature, out error), error);
            settings.MinimumDetectionConfidence = 0.2F;
            AssertTrue(YoloPythonClientProcessService.TryCreateStartSignature(settings, out string changedConfidenceSignature, out error), error);
            AssertTrue(
                !string.Equals(firstSignature, changedConfidenceSignature, StringComparison.Ordinal),
                "confidence changes should change Python client start signature");

            settings.MinimumDetectionConfidence = 0.15F;
            settings.InferenceImageSize = 416;
            AssertTrue(YoloPythonClientProcessService.TryCreateStartSignature(settings, out string changedImageSizeSignature, out error), error);
            AssertTrue(
                !string.Equals(firstSignature, changedImageSizeSignature, StringComparison.Ordinal),
                "inference image size changes should change Python client start signature");

            settings.InferenceImageSize = 320;
            settings.WeightsPath = Path.Combine(root, "other.pt");
            AssertTrue(YoloPythonClientProcessService.TryCreateStartSignature(settings, out string changedWeightsSignature, out error), error);
            AssertTrue(
                !string.Equals(firstSignature, changedWeightsSignature, StringComparison.Ordinal),
                "weight path changes should change Python client start signature");

            settings.ClientScriptPath = Path.Combine(root, "missing.py");
            AssertTrue(!YoloPythonClientProcessService.TryCreateStartInfo(settings, out _, out error), "missing client script was accepted");
            AssertTrue(error.Contains("not found"), "missing client script error was not descriptive");
        }
        finally
        {
            DeleteTempRoot(root);
        }
    }

    private static void TestYoloDetectionWorkflowValidation()
    {
        string root = CreateTempRoot();
        try
        {
            string scriptPath = Path.Combine(root, "labelling_tcp_client.py");
            string weightsPath = Path.Combine(root, "best.pt");
            File.WriteAllText(scriptPath, "print('ready')");

            var data = new CData();
            data.ProjectSettings.PythonModel.ProjectRootPath = root;
            data.ProjectSettings.PythonModel.ClientScriptPath = scriptPath;
            data.ProjectSettings.PythonModel.WeightsPath = Path.Combine(root, "missing.pt");
            data.ProjectSettings.PythonModel.ImageRootPath = root;

            using var communication = new CCommunicationLearning(startListen: false);
            var workflow = new YoloDetectionWorkflowService();
            bool ensureCalled = false;
            bool invalidStarted = workflow.TryStartCurrentImageDetection(
                data,
                communication,
                new DetectionResultApplicationService(),
                () =>
                {
                    ensureCalled = true;
                    return true;
                });

            AssertTrue(!invalidStarted, "detection workflow should reject missing weights");
            AssertTrue(!ensureCalled, "Python client should not be prepared when detection settings are invalid");

            File.WriteAllText(weightsPath, "");
            data.ProjectSettings.PythonModel.WeightsPath = weightsPath;
            bool readyFailureStarted = workflow.TryStartCurrentImageDetection(
                data,
                communication,
                new DetectionResultApplicationService(),
                () =>
                {
                    ensureCalled = true;
                    return false;
                });

            AssertTrue(!readyFailureStarted, "detection workflow should stop when the Python client is not ready");
            AssertTrue(ensureCalled, "Python client readiness was not checked for valid settings");

            string imagePath = Path.Combine(root, "detect-yolo11.jpg");
            using (var image = new Bitmap(8, 8))
            {
                image.Save(imagePath, System.Drawing.Imaging.ImageFormat.Jpeg);
            }

            data.ProjectSettings.PythonModel.ModelEngine = PythonModelSettings.EngineYolo11;
            int detectPort = GetAvailableTcpPort();
            using var detectCommunication = new CCommunicationLearning(startListen: false, port: detectPort);
            using var receivedDetectRequest = new ManualResetEventSlim(false);
            AssertTrue(detectCommunication.Start(), "test TCP listener for DetectImage did not start");
            Task mockDetectClient = Task.Run(() => RunMockDetectImageClient(detectPort, receivedDetectRequest, "yolo11"));
            AssertTrue(WaitUntil(() => detectCommunication.GetStatusSnapshot().IsClientConnected, TimeSpan.FromSeconds(5)), "mock DetectImage client did not connect");

            var detectionService = new DetectionResultApplicationService();
            bool detectStarted = workflow.TryStartImagePathDetection(
                data,
                detectCommunication,
                detectionService,
                imagePath,
                new Size(8, 8),
                () => true);

            AssertTrue(detectStarted, "detection workflow should send DetectImage when settings and image path are valid");
            AssertTrue(receivedDetectRequest.Wait(TimeSpan.FromSeconds(5)), "mock DetectImage client did not receive the request");
            AssertTrue(mockDetectClient.Wait(TimeSpan.FromSeconds(5)), "mock DetectImage client did not finish");
            if (mockDetectClient.IsFaulted)
            {
                if (mockDetectClient.Exception != null)
                {
                    throw mockDetectClient.Exception;
                }

                throw new InvalidOperationException("mock DetectImage client failed");
            }
        }
        finally
        {
            DeleteTempRoot(root);
        }
    }

    private static void TestRuntimeCommandFailureMessages()
    {
        string repositoryRoot = FindRepositoryRoot();
        string detectionResultSource = File.ReadAllText(Path.Combine(repositoryRoot, "1. Core", "DetectionResultApplicationService.cs"));
        string detectionWorkflowSource = File.ReadAllText(Path.Combine(repositoryRoot, "1. Core", "YoloDetectionWorkflowService.cs"));
        string trainingWorkflowSource = File.ReadAllText(Path.Combine(repositoryRoot, "1. Core", "YoloTrainingWorkflowService.cs"));
        string combinedSource = string.Concat(detectionResultSource, detectionWorkflowSource, trainingWorkflowSource);

        string[] previousEnglishMessages =
        {
            "YOLO detection communication is not initialized.",
            "YOLO detection result service is not initialized.",
            "YOLO detection data is not initialized.",
            "StartDefect skipped because source image is empty.",
            "DetectImage skipped because image path is missing",
            "DetectImage skipped because image size is empty",
            "DetectImage was not sent because the Python model client is not connected.",
            "Selected detection candidate cannot be skipped because the active image changed.",
            "YOLO detection timed out after",
            "YOLO training communication is not initialized.",
            "StartTraining was not sent because the Python model client is not connected.",
            "StopTraining was not sent because the Python model client is not connected.",
            "YOLO training validation failed:"
        };

        foreach (string previousMessage in previousEnglishMessages)
        {
            AssertTrue(!combinedSource.Contains(previousMessage, StringComparison.Ordinal), $"old English runtime failure message remains: {previousMessage}");
        }

        AssertTrue(combinedSource.Contains("Python 모델 클라이언트가 연결되지 않아 현재 검사 요청을 보내지 못했습니다.", StringComparison.Ordinal), "current-inspection disconnect message should be Korean");
        AssertTrue(combinedSource.Contains("Python 모델 클라이언트가 연결되지 않아 학습 시작 명령을 보내지 못했습니다.", StringComparison.Ordinal), "training disconnect message should be Korean");
        AssertTrue(combinedSource.Contains("YOLO 검사 시간이 초과되었습니다.", StringComparison.Ordinal), "detection timeout message should be Korean");
        AssertTrue(!ContainsVisibleMojibakeArtifact(combinedSource), "runtime command failure sources should not expose mojibake artifacts");

        string root = CreateTempRoot();
        try
        {
            string scriptPath = Path.Combine(root, "labelling_tcp_client.py");
            string weightsPath = Path.Combine(root, "best.pt");
            string pythonPath = Path.Combine(root, "python.exe");
            File.WriteAllText(scriptPath, "print('ready')");
            File.WriteAllText(weightsPath, "");
            File.WriteAllText(pythonPath, "");

            var data = new CData();
            data.ProjectSettings.PythonModel.ProjectRootPath = root;
            data.ProjectSettings.PythonModel.ClientScriptPath = scriptPath;
            data.ProjectSettings.PythonModel.PythonExecutablePath = pythonPath;
            data.ProjectSettings.PythonModel.WeightsPath = weightsPath;
            data.ProjectSettings.PythonModel.ImageRootPath = root;

            using var communication = new CCommunicationLearning(startListen: false);
            var workflow = new YoloDetectionWorkflowService();

            bool missingImageStarted = workflow.TryStartImagePathDetection(
                data,
                communication,
                new DetectionResultApplicationService(),
                Path.Combine(root, "missing.jpg"),
                new Size(10, 10),
                () => true);

            AssertTrue(!missingImageStarted, "detection workflow should reject a missing image path");
            AssertTrue(communication.GetStatusSnapshot().LastError.Contains("검사 이미지 파일", StringComparison.Ordinal), "missing-image LastError should be operator-readable Korean");

            string imagePath = Path.Combine(root, "image.jpg");
            using (var image = new Bitmap(4, 4))
            {
                image.Save(imagePath, System.Drawing.Imaging.ImageFormat.Jpeg);
            }

            bool emptySizeStarted = workflow.TryStartImagePathDetection(
                data,
                communication,
                new DetectionResultApplicationService(),
                imagePath,
                Size.Empty,
                () => true);

            AssertTrue(!emptySizeStarted, "detection workflow should reject an empty image size");
            AssertTrue(communication.GetStatusSnapshot().LastError.Contains("이미지 크기", StringComparison.Ordinal), "empty-size LastError should be operator-readable Korean");

            bool nullDataStarted = workflow.TryStartCurrentImageDetection(
                null,
                communication,
                new DetectionResultApplicationService(),
                () => true);

            AssertTrue(!nullDataStarted, "detection workflow should reject null data");
            AssertTrue(communication.GetStatusSnapshot().LastError.Contains("검사 데이터", StringComparison.Ordinal), "null-data LastError should be operator-readable Korean");
        }
        finally
        {
            DeleteTempRoot(root);
        }
    }

    private static void TestPythonMessageFramer()
    {
        var framer = new PythonMessageFramer();

        IReadOnlyList<string> first = framer.Append("ResultDefect [{\"ClassName\":\"NG\",");
        AssertEqual(0, first.Count);

        IReadOnlyList<string> second = framer.Append("\"Confidence\":0.9,\"X\":1,\"Y\":2,\"Width\":3,\"Height\":4}]");
        AssertEqual(1, second.Count);
        AssertTrue(second[0].StartsWith("ResultDefect ", StringComparison.Ordinal), "split ResultDefect was not rebuilt");

        DetectionResultParseResult result = PythonDetectionResultProtocol.Parse(second[0]);
        AssertEqual(DetectionResultParseStatus.Parsed, result.Status);
        AssertEqual("NG", result.Defects[0].ClassName);

        var separatedFramer = new PythonMessageFramer();
        IReadOnlyList<string> separated = separatedFramer.Append("ResultDefect\n\n[{\"ClassName\":\"OK\",\"Confidence\":0.8,\"X\":1,\"Y\":2,\"Width\":3,\"Height\":4}]");
        AssertEqual(1, separated.Count);
        AssertEqual(DetectionResultParseStatus.Parsed, PythonDetectionResultProtocol.Parse(separated[0]).Status);

        IReadOnlyList<string> commands = framer.Append("StartTraining\nStopTraining\n");
        AssertEqual(2, commands.Count);
        AssertEqual("StartTraining", commands[0]);
        AssertEqual("StopTraining", commands[1]);

        var envelopeFramer = new PythonMessageFramer();
        IReadOnlyList<string> envelopeFirst = envelopeFramer.Append("{\"type\":\"ResultDefect\",\"items\":[");
        AssertEqual(0, envelopeFirst.Count);

        IReadOnlyList<string> envelopeSecond = envelopeFramer.Append("{\"className\":\"OK\",\"confidence\":0.7,\"x\":1,\"y\":2,\"width\":3,\"height\":4}]}");
        AssertEqual(1, envelopeSecond.Count);
        AssertEqual(DetectionResultParseStatus.Parsed, PythonDetectionResultProtocol.Parse(envelopeSecond[0]).Status);
    }

    private static void TestPythonModelStatusProtocol()
    {
        string statusJson = "{\"type\":\"TrainingStatus\",\"version\":1,\"state\":\"running\",\"message\":\"epoch\",\"progressPercent\":42,\"epoch\":2,\"totalEpochs\":5}";

        PythonModelStatusParseResult result = PythonModelStatusProtocol.Parse(statusJson);

        AssertEqual(PythonModelStatusParseStatus.Parsed, result.Status);
        AssertEqual("running", result.Message.State);
        AssertEqual(42, result.Message.ProgressPercent.Value);
        AssertEqual(2, result.Message.Epoch.Value);
        AssertEqual(5, result.Message.TotalEpochs.Value);
        AssertTrue(!result.Message.IsError, "running status should not be an error");

        string trainResultJson = "{\"type\":\"TrainYoloResult\",\"version\":1,\"ok\":true,\"taskId\":\"task-1\",\"state\":\"started\"}";
        PythonModelStatusParseResult trainResult = PythonModelStatusProtocol.Parse(trainResultJson);
        AssertEqual(PythonModelStatusParseStatus.Parsed, trainResult.Status);
        AssertEqual(PythonModelStatusProtocol.TrainingStatusType, trainResult.Message.Type);
        AssertEqual("started", trainResult.Message.State);

        string taskStatusJson = "{\"type\":\"TaskStatus\",\"version\":1,\"taskType\":\"TrainYolo\",\"taskId\":\"task-1\",\"state\":\"completed\",\"message\":\"YOLOv5 training completed.\",\"progressPercent\":100}";
        PythonModelStatusParseResult taskStatus = PythonModelStatusProtocol.Parse(taskStatusJson);
        AssertEqual(PythonModelStatusParseStatus.Parsed, taskStatus.Status);
        AssertEqual(PythonModelStatusProtocol.TrainingStatusType, taskStatus.Message.Type);
        AssertEqual("completed", taskStatus.Message.State);
        AssertEqual(100, taskStatus.Message.ProgressPercent.Value);

        string failedTaskStatusJson = "{\"type\":\"TaskStatus\",\"version\":1,\"taskType\":\"TrainYolo\",\"taskId\":\"task-2\",\"state\":\"failed\",\"message\":\"YOLOv5 training failed.\",\"exitCode\":1,\"logTail\":[\"Starting training for 1 epochs...\",\"Epoch GPU_mem box_loss obj_loss cls_loss Instances Size\",\"0%| | 0/7 [00:00<?, ?it/s]\"]}";
        PythonModelStatusParseResult failedTaskStatus = PythonModelStatusProtocol.Parse(failedTaskStatusJson);
        AssertEqual(PythonModelStatusParseStatus.Parsed, failedTaskStatus.Status);
        AssertTrue(failedTaskStatus.Message.Message.Contains("first training batch", StringComparison.OrdinalIgnoreCase), "failed training status should infer a user-actionable first-batch failure reason");

        string healthJson = "{\"type\":\"HealthCheckResult\",\"version\":1,\"requestId\":\"req-health\",\"ok\":true,\"state\":\"ready\",\"worker\":{\"pid\":123,\"capabilities\":{\"models\":[\"yolov5\",\"yolo11\"],\"training\":[\"yolo11\"],\"inspection\":[\"yolo11\"]}}}";
        PythonModelStatusParseResult health = PythonModelStatusProtocol.Parse(healthJson);
        AssertEqual(PythonModelStatusParseStatus.Parsed, health.Status);
        AssertEqual(PythonModelStatusProtocol.HealthCheckResultType, health.Message.Type);
        AssertEqual("ready", health.Message.State);
        AssertTrue(health.Message.Ok == true, "health check ok state was not parsed");
        AssertTrue(health.Message.SupportedModels.Contains("yolo11"), "health check should parse worker supported model capabilities");
        AssertTrue(health.Message.TrainingModels.Contains("yolo11"), "health check should parse worker training capabilities");
        AssertTrue(health.Message.DetectionModels.Contains("yolo11"), "health check should parse worker detection capabilities");

        string modelJson = "{\"type\":\"ModelStatusResult\",\"version\":1,\"requestId\":\"req-model\",\"ok\":true,\"capabilities\":{\"supportedModels\":\"yolov5,yolov8\",\"trainingModels\":[\"yolov8\"],\"detectionModels\":[\"yolov8\"]},\"model\":{\"state\":\"ready\",\"loaded\":true,\"weightsPath\":\"C:/Git/yolov5/best.pt\"}}";
        PythonModelStatusParseResult model = PythonModelStatusProtocol.Parse(modelJson);
        AssertEqual(PythonModelStatusParseStatus.Parsed, model.Status);
        AssertEqual(PythonModelStatusProtocol.ModelStatusResultType, model.Message.Type);
        AssertEqual("ready", model.Message.State);
        AssertTrue(model.Message.Loaded == true, "model loaded state was not parsed");
        AssertTrue(model.Message.SupportedModels.Contains("yolov8"), "model status should parse supported model capabilities");

        PythonModelStatusParseResult ignored = PythonModelStatusProtocol.Parse("{\"type\":\"Other\"}");
        AssertEqual(PythonModelStatusParseStatus.NotStatus, ignored.Status);
    }

