    private static void TestRoiGeometry()
    {
        Rectangle roi = RoiGeometry.CreateBoundedRectangle(
            new Point(50, 60),
            new Point(-10, 200),
            new Rectangle(0, 0, 100, 100));

        AssertEqual(new Rectangle(0, 60, 50, 40), roi);

        AssertTrue(OpenVisionLab.ImageCanvas.RoiInteractionMouseMove.TryCreateClippedCanvasRect(
            new PointF(-25, 125),
            new PointF(35, 65),
            new Size(100, 100),
            out float left,
            out float top,
            out float right,
            out float bottom), "canvas ROI drag should remain valid after clipping to image bounds");
        AssertEqual(0F, left);
        AssertEqual(100F, top);
        AssertEqual(35F, right);
        AssertEqual(65F, bottom);
        AssertTrue(!OpenVisionLab.ImageCanvas.RoiInteractionMouseMove.TryCreateClippedCanvasRect(
            new PointF(-25, 20),
            new PointF(-5, 80),
            new Size(100, 100),
            out _,
            out _,
            out _,
            out _), "canvas ROI drag fully outside one image edge should not commit a visible rectangle");
        AssertTrue(!OpenVisionLab.ImageCanvas.RoiInteractionMouseMove.TryCreateClippedCanvasRect(
            new PointF(105, 20),
            new PointF(130, 80),
            new Size(100, 100),
            out _,
            out _,
            out _,
            out _), "canvas ROI drag fully outside the right image edge should not commit a visible rectangle");
        AssertTrue(!OpenVisionLab.ImageCanvas.RoiInteractionMouseMove.TryCreateClippedCanvasRect(
            new PointF(20, 105),
            new PointF(80, 130),
            new Size(100, 100),
            out _,
            out _,
            out _,
            out _), "canvas ROI drag fully outside the top image edge should not commit a visible rectangle");
        AssertTrue(!OpenVisionLab.ImageCanvas.RoiInteractionMouseMove.TryCreateClippedCanvasRect(
            new PointF(20, -30),
            new PointF(80, -5),
            new Size(100, 100),
            out _,
            out _,
            out _,
            out _), "canvas ROI drag fully outside the bottom image edge should not commit a visible rectangle");

        var canvasRoi = new CanvasRect<float>(10, 60, 70, 10);
        AssertEqual(LineOverType.Move2D, canvasRoi.GetHandleContainsPoint(22, 35, 0.2F, 20F));
        canvasRoi.SetEditingType(22, 35, 0.2F, 20F);
        AssertEqual(EditingType.Move, canvasRoi.EditingType);
        AssertEqual(LineOverType.VSplit, canvasRoi.GetHandleContainsPoint(11, 35, 0.2F, 20F));
        canvasRoi.SetEditingType(11, 35, 0.2F, 20F);
        AssertEqual(EditingType.Left, canvasRoi.EditingType);
        AssertEqual(LineOverType.SizeNWSE, canvasRoi.GetHandleContainsPoint(12, 58, 0.2F, 20F));
        canvasRoi.SetEditingType(12, 58, 0.2F, 20F);
        AssertEqual(EditingType.LeftTop, canvasRoi.EditingType);
        AssertEqual(LineOverType.VSplit, canvasRoi.GetHandleContainsPoint(10, 35, 0.2F, 20F));
        AssertEqual(LineOverType.VSplit, canvasRoi.GetHandleContainsPoint(9, 35, 0.2F, 20F));
        AssertEqual(LineOverType.None, canvasRoi.CheckHandleContainsPosition(9, 35, 0.2F, 20F));
        canvasRoi.SetEditingType(9, 35, 0.2F, 20F);
        AssertEqual(EditingType.Left, canvasRoi.EditingType);
        AssertEqual(LineOverType.SizeNWSE, canvasRoi.GetHandleContainsPoint(10, 60, 0.2F, 20F));
        AssertEqual(LineOverType.SizeNWSE, canvasRoi.GetHandleContainsPoint(9, 61, 0.2F, 20F));
        AssertEqual(LineOverType.None, canvasRoi.CheckHandleContainsPosition(9, 61, 0.2F, 20F));
        const float handleScreenPixels = 14F;
        AssertNearlyEqual(
            handleScreenPixels,
            OpenVisionLab.ImageCanvas.OpenGLRendering.OpenGlDrawing.GetRoiEditHandleWorldSize(0.2F, handleScreenPixels) / 0.2F,
            0.001F,
            "zoomed-in ROI handle screen size");
        AssertNearlyEqual(
            handleScreenPixels,
            OpenVisionLab.ImageCanvas.OpenGLRendering.OpenGlDrawing.GetRoiEditHandleWorldSize(1F, handleScreenPixels) / 1F,
            0.001F,
            "actual-size ROI handle screen size");
        AssertNearlyEqual(
            handleScreenPixels,
            OpenVisionLab.ImageCanvas.OpenGLRendering.OpenGlDrawing.GetRoiEditHandleWorldSize(2F, handleScreenPixels) / 2F,
            0.001F,
            "zoomed-out ROI handle screen size");

        string devCanvasPath = Path.GetFullPath(Path.Combine(FindRepositoryRoot(), "..", "OpenVisionLab_Dev", "Library", "OpenVisionLab.ImageCanvas", "Compatibility", "CanvasCompatibility.cs"));
        if (File.Exists(devCanvasPath))
        {
            string devCanvasSource = File.ReadAllText(devCanvasPath);
            AssertTrue(devCanvasSource.Contains("LineOverType.VSplit", StringComparison.Ordinal), "OpenVisionLab_Dev ImageCanvas should keep explicit ROI edge hit-test support");
            AssertTrue(!devCanvasSource.Contains("float tolerance = GetHitTolerance(zoomScale, handleSize);", StringComparison.Ordinal), "OpenVisionLab_Dev ImageCanvas should not keep the old single wide ROI hit tolerance");
        }
    }

    private static void TestRoiGeometrySuppressesExtendedCallbacksDuringDrag()
    {
        var canvasRoi = new CanvasRect<float>(10, 60, 70, 10);
        canvasRoi.CreateExtendedRectangleFromSize();
        int mainChanged = 0;
        int extendedChanged = 0;
        canvasRoi.OnChanged = () => mainChanged++;
        canvasRoi.ExtendedRectangle.OnChanged = () => extendedChanged++;

        canvasRoi.OffsetMove(new CanvasSize<float>(5, 0), notify: false);
        canvasRoi.SetEditingType(75, 35, 1F, 10F);
        canvasRoi.Move(80, 35, new Size(200, 200), notify: false);

        AssertEqual(0, mainChanged);
        AssertEqual(0, extendedChanged);
        AssertTrue(canvasRoi.IsChanged, "main ROI should still be marked dirty while suppressing MouseMove display-list callbacks");
        AssertTrue(canvasRoi.ExtendedRectangle.IsChanged, "extended ROI should still be marked dirty for the committed mouse-up rebuild");

        canvasRoi.OffsetMove(new CanvasSize<float>(1, 0), notify: true);
        AssertEqual(1, mainChanged);
        AssertEqual(1, extendedChanged);
    }

