        AssertTrue(wizardViewModelSource.Contains("WpfDatasetSetupRequest", StringComparison.Ordinal), "dataset setup wizard should build a request DTO instead of writing files");
        AssertTrue(wizardViewModelSource.Contains("TryBuildRequest", StringComparison.Ordinal), "dataset setup wizard should validate before create");
        AssertTrue(wizardViewModelSource.Contains("ParseClassNames", StringComparison.Ordinal), "dataset setup wizard should parse comma/newline class names");
        AssertTrue(shellSource.Contains("WpfDatasetSetupWizardWindow", StringComparison.Ordinal), "dataset setup command should open the guided wizard");
        AssertTrue(shellSource.Contains("ApplyDatasetSetupRequest", StringComparison.Ordinal), "dataset setup persistence should be isolated behind a request application method");
        AssertTrue(shellSource.Contains("WpfDatasetSetupPathService", StringComparison.Ordinal), "dataset setup shell should delegate recipe/output path decisions to a service");
        AssertTrue(shellSource.Contains("WpfDatasetSetupDataService", StringComparison.Ordinal), "dataset setup shell should delegate CData materialization to a service");
        AssertTrue(shellSource.Contains("WpfDatasetSetupPresentationService", StringComparison.Ordinal), "dataset setup shell should delegate operator-facing status text to a service");
        AssertTrue(datasetSetupPathServiceSource.Contains("ResolveRecipeName", StringComparison.Ordinal), "dataset setup path service should own recipe-name selection");
        AssertTrue(datasetSetupPathServiceSource.Contains("TryFindDatasetUsingOutputRoot", StringComparison.Ordinal), "dataset setup path service should own output-root collision detection");
        AssertTrue(datasetSetupDataServiceSource.Contains("ApplyOutputRootAndClasses", StringComparison.Ordinal), "dataset setup data service should own output-root and class materialization");
        AssertTrue(datasetSetupPresentationServiceSource.Contains("BuildDuplicateOutputRootMessage", StringComparison.Ordinal), "dataset setup presentation service should own duplicate-folder guidance");
        AssertTrue(datasetSetupPresentationServiceSource.Contains("BuildReadyStatus", StringComparison.Ordinal), "dataset setup presentation service should own ready status wording");
        AssertTrue(datasetSetupPresentationServiceSource.Contains("BuildMissingImageRootStatus", StringComparison.Ordinal), "dataset setup presentation service should own missing-image-folder status wording");
        AssertTrue(datasetSetupPresentationServiceSource.Contains("BuildMissingOutputRootStatus", StringComparison.Ordinal), "dataset setup presentation service should own missing-storage-folder status wording");
        AssertTrue(!shellSource.Contains("private bool CanUseRecipeNameForNewDataset", StringComparison.Ordinal), "dataset setup shell should not own recipe-name availability checks");
        AssertTrue(!shellSource.Contains("private string BuildUniqueDatasetSetupRecipeName", StringComparison.Ordinal), "dataset setup shell should not own unique recipe-name generation");
        AssertTrue(!shellSource.Contains("private bool TryFindDatasetUsingOutputRoot", StringComparison.Ordinal), "dataset setup shell should not scan recipe configs for output-root collisions");
        string applyDatasetSetupSource = FindMethodSourceBlock(shellSource, "private bool ApplyDatasetSetupRequest(WpfDatasetSetupRequest request)");
        AssertTrue(applyDatasetSetupSource.Contains("datasetSetupDataService.ApplyOutputRootAndClasses", StringComparison.Ordinal),
            "dataset setup apply should materialize output root and classes through the data service");
        AssertTrue(applyDatasetSetupSource.Contains("datasetSetupPresentationService.BuildDuplicateOutputRootMessage", StringComparison.Ordinal),
            "dataset setup apply should build duplicate output-root guidance through the presentation service");
        AssertTrue(applyDatasetSetupSource.Contains("datasetSetupPresentationService.BuildReadyStatus", StringComparison.Ordinal),
            "dataset setup apply should build final ready status through the presentation service");
        AssertTrue(!applyDatasetSetupSource.Contains("ClassNamedList.Clear", StringComparison.Ordinal),
            "dataset setup apply should not mutate the class catalog inline");
        string clearQueueAfterDatasetSwitchSource = FindMethodSourceBlock(shellSource, "private void ClearImageQueueAfterDatasetSwitch(string imageRootPath)");
        AssertTrue(clearQueueAfterDatasetSwitchSource.Contains("datasetSetupPresentationService.BuildMissingImageRootStatus", StringComparison.Ordinal),
            "dataset switch should build missing-image-folder status through the presentation service");
        string openDatasetRootFolderSource = FindMethodSourceBlock(shellSource, "private void ExecuteOpenDatasetRootFolderCommand()");
        AssertTrue(openDatasetRootFolderSource.Contains("datasetSetupPresentationService.BuildMissingOutputRootStatus", StringComparison.Ordinal),
            "dataset folder open should build missing-storage-folder status through the presentation service");
        AssertTrue(openDatasetRootFolderSource.Contains("datasetSetupPresentationService.BuildOpenDatasetFolderFailedStatus", StringComparison.Ordinal),
            "dataset folder open should build failure status through the presentation service");

        AssertEqual("None", selectionXaml.Root?.Attribute("WindowStyle")?.Value);
        AssertTrue(
            selectionXaml.Descendants().Any(element => string.Equals(element.Name.LocalName, "WpfWindowTitleBar", StringComparison.Ordinal)),
            "dataset selection window should use the shared custom title bar");
        AssertNamedXamlElement(selectionXaml, xName, "Border", "DatasetSourceRuleCard");
        AssertNamedXamlElement(selectionXaml, xName, "TextBlock", "DatasetSourceRuleTitleText");
        AssertNamedXamlElement(selectionXaml, xName, "TextBlock", "DatasetSourceRuleDetailText");
        AssertNamedXamlElement(selectionXaml, xName, "ListBox", "DatasetSelectionListBox");
        AssertNamedXamlElement(selectionXaml, xName, "Border", "ExistingDatasetOpenGuideCard");
        AssertNamedXamlElement(selectionXaml, xName, "TextBlock", "ExistingDatasetGuideTitleText");
        AssertNamedXamlElement(selectionXaml, xName, "TextBlock", "ExistingDatasetGuideDetailText");
        AssertNamedXamlElement(selectionXaml, xName, "Border", "CreateDatasetGuideCard");
        AssertNamedXamlElement(selectionXaml, xName, "TextBlock", "CreateDatasetGuideTitleText");
        AssertNamedXamlElement(selectionXaml, xName, "TextBlock", "CreateDatasetGuideDetailText");
        AssertNamedXamlElement(selectionXaml, xName, "Border", "DatasetSelectionEmptyStatePanel");
        AssertNamedXamlElement(selectionXaml, xName, "TextBlock", "DatasetSelectionStatusText");
        AssertNamedXamlElement(selectionXaml, xName, "Button", "RefreshDatasetSelectionButton");
        AssertNamedXamlElement(selectionXaml, xName, "Button", "CreateDatasetGuideButton");
        AssertNamedXamlElement(selectionXaml, xName, "Button", "CreateFirstDatasetButton");
        AssertNamedXamlElement(selectionXaml, xName, "Button", "CreateNewDatasetFromSelectionButton");
        AssertNamedXamlElement(selectionXaml, xName, "Button", "CancelDatasetSelectionButton");
        AssertNamedXamlElement(selectionXaml, xName, "Button", "OpenSelectedDatasetButton");
        AssertNamedXamlBinding(selectionXaml, xName, "DatasetSelectionListBox", "ItemsSource", "Datasets");
        AssertNamedXamlBinding(selectionXaml, xName, "DatasetSelectionListBox", "SelectedItem", "SelectedDataset");
        AssertNamedXamlBinding(selectionXaml, xName, "DatasetSelectionEmptyStatePanel", "Visibility", "EmptyStateVisibility");
        AssertNamedXamlBinding(selectionXaml, xName, "DatasetSourceRuleTitleText", "Text", "DatasetSourceRuleTitleText");
        AssertNamedXamlBinding(selectionXaml, xName, "DatasetSourceRuleDetailText", "Text", "DatasetSourceRuleDetailText");
        AssertNamedXamlBinding(selectionXaml, xName, "ExistingDatasetGuideTitleText", "Text", "ExistingDatasetGuideTitleText");
        AssertNamedXamlBinding(selectionXaml, xName, "ExistingDatasetGuideDetailText", "Text", "ExistingDatasetGuideDetailText");
        AssertNamedXamlBinding(selectionXaml, xName, "CreateDatasetGuideTitleText", "Text", "CreateDatasetGuideTitleText");
        AssertNamedXamlBinding(selectionXaml, xName, "CreateDatasetGuideDetailText", "Text", "CreateDatasetGuideDetailText");
        AssertNamedXamlBinding(selectionXaml, xName, "DatasetSelectionStatusText", "Text", "StatusText");
        AssertTrue(selectionXaml.ToString().Contains("StoragePathText", StringComparison.Ordinal), "dataset selector should label the storage path role");
        AssertTrue(selectionXaml.ToString().Contains("ImageRootPathText", StringComparison.Ordinal), "dataset selector should label the source image folder role");
        AssertTrue(selectionXaml.ToString().Contains("ImageRootPath", StringComparison.Ordinal), "dataset selector should show the image folder path for each dataset");
        AssertNamedXamlBinding(selectionXaml, xName, "RefreshDatasetSelectionButton", "Command", "RefreshCommand");
        AssertNamedXamlBinding(selectionXaml, xName, "CreateDatasetGuideButton", "Command", "CreateNewCommand");
        AssertNamedXamlBinding(selectionXaml, xName, "CreateFirstDatasetButton", "Command", "CreateNewCommand");
        AssertNamedXamlBinding(selectionXaml, xName, "CreateNewDatasetFromSelectionButton", "Command", "CreateNewCommand");
        AssertNamedXamlBinding(selectionXaml, xName, "CancelDatasetSelectionButton", "Command", "CancelCommand");
        AssertNamedXamlBinding(selectionXaml, xName, "OpenSelectedDatasetButton", "Command", "OpenCommand");

        string selectionViewModelSource = File.ReadAllText(selectionViewModelPath);
        AssertTrue(selectionViewModelSource.Contains("LoadDatasets", StringComparison.Ordinal), "dataset selection ViewModel should load existing recipes");
        AssertTrue(selectionViewModelSource.Contains("WpfDatasetSelectionItem", StringComparison.Ordinal), "dataset selection ViewModel should expose selection rows");
        AssertTrue(selectionViewModelSource.Contains("CreateNewCommand", StringComparison.Ordinal), "dataset selection ViewModel should keep creation as a separate command");
        AssertTrue(shellSource.Contains("WpfDatasetSelectionWindow", StringComparison.Ordinal), "dataset change should open a dataset selector before any create flow");
        AssertTrue(shellSource.Contains("ApplySelectedDatasetRecipe", StringComparison.Ordinal), "dataset selector should apply an existing recipe without recreating it");

        string emptySelectionRoot = CreateTempRoot();
        try
        {
            var selectionViewModel = new WpfDatasetSelectionWindowViewModel();
            selectionViewModel.LoadDatasets(emptySelectionRoot, string.Empty);
            AssertTrue(selectionViewModel.DatasetSourceRuleDetailText.Contains("\uC800\uC7A5 \uD3F4\uB354", StringComparison.Ordinal),
                "dataset selector should explain that storage folder is the label baseline");
            AssertTrue(selectionViewModel.DatasetSourceRuleDetailText.Contains("\uC774\uBBF8\uC9C0 \uD3F4\uB354", StringComparison.Ordinal),
                "dataset selector should explain that image folder is only the source image list");
            AssertTrue(selectionViewModel.CreateDatasetGuideDetailText.Contains("\uB77C\uBCA8", StringComparison.Ordinal),
                "dataset selector creation guide should explicitly say labels do not carry over when storage is new");
            AssertEqual(System.Windows.Visibility.Visible, selectionViewModel.EmptyStateVisibility);
            AssertTrue(selectionViewModel.StatusText.Contains("\uC0C8 \uB370\uC774\uD130\uC14B", StringComparison.Ordinal),
                "empty dataset selector state should point directly to creating a new dataset");
        }
        finally
        {
            DeleteTempRoot(emptySelectionRoot);
        }

        string pathServiceRoot = CreateTempRoot();
        try
        {
            var pathService = new WpfDatasetSetupPathService();
            string recipeRoot = Path.Combine(pathServiceRoot, "recipes");
            string outputRoot = Path.Combine(pathServiceRoot, "DATA");
            Directory.CreateDirectory(recipeRoot);
            Directory.CreateDirectory(outputRoot);
            string availableRecipeName = pathService.ResolveRecipeName("NewRecipe", "CurrentRecipe", LabelingDatasetPurpose.ObjectDetection, recipeRoot);
            AssertEqual("NewRecipe", availableRecipeName);

            Directory.CreateDirectory(WpfProjectRecipeService.BuildConfigDirectory(recipeRoot, "TakenRecipe"));
            string currentFallbackRecipeName = pathService.ResolveRecipeName("TakenRecipe", "CurrentRecipe", LabelingDatasetPurpose.ObjectDetection, recipeRoot);
            AssertEqual("CurrentRecipe", currentFallbackRecipeName);

            Directory.CreateDirectory(Path.Combine(outputRoot, "NewRecipe"));
            Directory.CreateDirectory(Path.Combine(outputRoot, "NewRecipe_2"));
            AssertEqual(Path.Combine(outputRoot, "NewRecipe_3"), pathService.ResolveOutputRoot("NewRecipe", outputRoot, recipeRoot));

            string existingRecipeDirectory = WpfProjectRecipeService.BuildConfigDirectory(recipeRoot, "ExistingRecipe");
            Directory.CreateDirectory(existingRecipeDirectory);
            string sharedOutputRoot = Path.Combine(outputRoot, "SharedOutput");
            File.WriteAllText(
                Path.Combine(existingRecipeDirectory, "VISION.xml"),
                $"<CData><ProjectSettings><YoloDataset><OutputRootPath>{System.Security.SecurityElement.Escape(sharedOutputRoot)}</OutputRootPath></YoloDataset></ProjectSettings></CData>");
            AssertTrue(pathService.TryFindDatasetUsingOutputRoot(recipeRoot, sharedOutputRoot, "NewRecipe", out string existingRecipeName),
                "dataset setup path service should detect another recipe using the same output root");
            AssertEqual("ExistingRecipe", existingRecipeName);
        }
        finally
        {
            DeleteTempRoot(pathServiceRoot);
        }

        string dataServiceRoot = CreateTempRoot();
        try
        {
            var dataService = new WpfDatasetSetupDataService();
            var setupData = new CData();
            string setupOutputRoot = Path.Combine(dataServiceRoot, "dataset-output");
            string selectedClassName = dataService.ApplyOutputRootAndClasses(setupData, setupOutputRoot, new[] { " OK ", "ok", "", "NG" });
            AssertEqual("OK", selectedClassName);
            AssertEqual(Path.GetFullPath(setupOutputRoot), Path.GetFullPath(setupData.OutputRootPath));
            AssertEqual(2, setupData.ClassNamedList.Count);
            AssertTrue(setupData.ClassNamedList.Any(item => string.Equals(item.Text, "OK", StringComparison.Ordinal)), "dataset setup data service should normalize and keep OK class");
            AssertTrue(setupData.ClassNamedList.Any(item => string.Equals(item.Text, "NG", StringComparison.Ordinal)), "dataset setup data service should normalize and keep NG class");
            AssertTrue(Directory.Exists(setupData.TrainImagesPath), "dataset setup data service should create train image directory");

            var fallbackData = new CData();
            string fallbackClassName = dataService.ApplyOutputRootAndClasses(fallbackData, Path.Combine(dataServiceRoot, "fallback-output"), Array.Empty<string>());
            AssertEqual("Defect", fallbackClassName);
            AssertEqual(1, fallbackData.ClassNamedList.Count);
            AssertEqual("Defect", fallbackData.ClassNamedList[0].Text);
        }
        finally
        {
            DeleteTempRoot(dataServiceRoot);
        }

        var presentationService = new WpfDatasetSetupPresentationService();
        string duplicateMessage = presentationService.BuildDuplicateOutputRootMessage("Recipe A");
        AssertTrue(duplicateMessage.Contains("Recipe A", StringComparison.Ordinal), "duplicate output-root guidance should name the existing dataset");
        AssertTrue(duplicateMessage.Contains("\uB2E4\uB978 \uBE48 \uD3F4\uB354", StringComparison.Ordinal), "duplicate output-root guidance should tell the operator to choose a different empty folder");
        AssertTrue(presentationService.BuildDuplicateOutputRootMessage(" ").Contains("\uAE30\uC874 \uB370\uC774\uD130\uC14B", StringComparison.Ordinal), "duplicate output-root guidance should have a readable fallback dataset name");
        AssertTrue(presentationService.BuildInvalidRecipeNameMessage().Contains("Recipe", StringComparison.Ordinal), "invalid recipe guidance should name the recipe field");
        AssertEqual("sample failed", presentationService.BuildSamplePresetFailureMessage(" sample failed "));
        AssertTrue(presentationService.BuildSamplePresetFailureMessage(" ").Contains("\uC0D8\uD50C \uB370\uC774\uD130\uC14B", StringComparison.Ordinal), "sample failure guidance should have a fallback message");
        var sampleResult = new WpfDatasetSamplePresetApplyResult
        {
            Applied = true,
            ImageRootPath = @"C:\SampleImages",
            SummaryText = "\uC0D8\uD50C 3\uC7A5"
        };
        string readyStatus = presentationService.BuildReadyStatus("Recipe A", LabelingDatasetPurpose.ObjectDetection, Path.Combine(root, "Recipe A", "dataset.json"), sampleResult);
        AssertTrue(readyStatus.Contains("Recipe A", StringComparison.Ordinal), "ready status should name the prepared recipe");
        AssertTrue(readyStatus.Contains(nameof(LabelingDatasetPurpose.ObjectDetection), StringComparison.Ordinal), "ready status should include the dataset purpose");
        AssertTrue(readyStatus.Contains("dataset.json", StringComparison.Ordinal), "ready status should include the manifest file name");
        AssertTrue(readyStatus.Contains("\uC0D8\uD50C 3\uC7A5", StringComparison.Ordinal), "ready status should append applied sample summary");
        AssertTrue(presentationService.BuildDatasetReadyStatus(Path.Combine(root, "OutputDataset")).Contains("OutputDataset", StringComparison.Ordinal), "dataset-ready status should show the output folder name");
        AssertTrue(presentationService.BuildCreationLog("Recipe A", LabelingDatasetPurpose.ObjectDetection, @"C:\DatasetOutput", @"C:\Manifest\dataset.json").Contains("manifest=", StringComparison.Ordinal), "creation log should keep manifest detail for troubleshooting");
        AssertTrue(presentationService.BuildMissingImageRootStatus().Contains("\uC774\uBBF8\uC9C0 \uD3F4\uB354", StringComparison.Ordinal), "missing-image-folder status should name the image folder");
        AssertTrue(presentationService.BuildMissingImageRootLog(@"C:\MissingImages").Contains(@"C:\MissingImages", StringComparison.Ordinal), "missing-image-folder log should keep the missing path for troubleshooting");
        AssertTrue(presentationService.BuildMissingOutputRootStatus().Contains("\uC800\uC7A5 \uACBD\uB85C", StringComparison.Ordinal), "missing-output-root status should name the storage path");
        AssertTrue(presentationService.BuildMissingOutputRootLog().Contains("\uB370\uC774\uD130\uC14B\uC744 \uB9CC\uB4E4", StringComparison.Ordinal), "missing-output-root log should tell the operator to create a dataset");
        AssertTrue(presentationService.BuildOpenDatasetFolderFailedStatus().Contains("\uD3F4\uB354 \uC5F4\uAE30 \uC2E4\uD328", StringComparison.Ordinal), "open-folder failed status should be short and operator-facing");
        AssertTrue(presentationService.BuildOpenDatasetFolderFailedLog("denied").Contains("denied", StringComparison.Ordinal), "open-folder failed log should keep the underlying error");

        WpfDatasetSetupWizardViewModel viewModel = new WpfDatasetSetupWizardViewModel();
        viewModel.LoadFrom(LabelingDatasetPurpose.Segmentation, "WizardRecipe", @"C:\Data\WizardRecipe", new[] { "Defect", "Scratch" });
        AssertEqual(LabelingDatasetPurpose.Segmentation, WpfLearningWorkflowPanelViewModel.ToDatasetPurpose(viewModel.SelectedDatasetPurposeMode.Mode));
        AssertTrue(viewModel.PreviewText.Contains("WizardRecipe", StringComparison.Ordinal), "wizard preview should include the recipe name");
        AssertTrue(viewModel.PreviewText.Contains("Scratch", StringComparison.Ordinal), "wizard preview should include initial classes");
        AssertTrue(viewModel.SetupSourceRuleDetailText.Contains("\uC800\uC7A5 \uD3F4\uB354", StringComparison.Ordinal), "wizard should explain the storage folder role before creation");
        AssertTrue(viewModel.SetupSourceRuleDetailText.Contains("\uC774\uBBF8\uC9C0 \uD3F4\uB354", StringComparison.Ordinal), "wizard should explain the image folder role before creation");
        AssertTrue(viewModel.SetupSourceRuleChecklistText.Contains("\uC0C8\uB85C \uC2DC\uC791", StringComparison.Ordinal), "wizard should give a short checklist for new dataset decisions");
        AssertTrue(viewModel.StorageHelpText.Contains("\uB77C\uBCA8", StringComparison.Ordinal), "wizard should explain where labels and recipe files are stored");
        AssertTrue(viewModel.ImageSourcePreviewText.Contains("\uC6D0\uBCF8 \uC774\uBBF8\uC9C0", StringComparison.Ordinal), "wizard should show the source image folder role");
        AssertTrue(viewModel.IsolationHelpText.Contains("\uBD84\uB9AC", StringComparison.Ordinal), "wizard should explain that storage folder isolation prevents label mixing");

        IReadOnlyList<string> parsed = WpfDatasetSetupWizardViewModel.ParseClassNames("OK, NG\r\nok; Defect");
        AssertEqual(3, parsed.Count);
        AssertEqual("OK", parsed[0]);
        AssertEqual("NG", parsed[1]);
        AssertEqual("Defect", parsed[2]);
        viewModel.ClassNamesText = "Defect, OK, NG";
        AssertTrue(viewModel.ClassSummaryText.Contains("3", StringComparison.Ordinal), "wizard should show how many classes will be created");
        AssertTrue(viewModel.ClassSummaryText.Contains("OK", StringComparison.Ordinal), "wizard class summary should include comma-separated class names");

        bool createRequested = false;
        bool cancelRequested = false;
        bool browseRequested = false;
        viewModel.ConfigureCommands(_ => createRequested = true, () => cancelRequested = true, () => browseRequested = true);
        viewModel.CreateCommand.Execute(null);
        viewModel.CancelCommand.Execute(null);
        viewModel.BrowseOutputRootCommand.Execute(null);
        AssertTrue(createRequested && cancelRequested && browseRequested, "wizard commands should be shell-injectable");
        AssertTrue(viewModel.TryBuildRequest(out WpfDatasetSetupRequest request, out string error), error);
        AssertEqual("WizardRecipe", request.RecipeName);
        AssertEqual(LabelingDatasetPurpose.Segmentation, request.Purpose);
        AssertEqual(3, request.ClassNames.Count);
        AssertTrue(request.ClassNames.Contains("NG"), "wizard request should create three classes from Defect, OK, NG input");

        viewModel.OutputRootPath = "";
        AssertTrue(!viewModel.TryBuildRequest(out _, out error) && !string.IsNullOrWhiteSpace(error), "wizard should reject an empty output root");

        string selectorRoot = CreateTempRoot();
        try
        {
            string currentRecipeName = "CurrentRecipe";
            string nextRecipeName = "NextRecipe";
            string currentRecipeDirectory = Path.Combine(selectorRoot, currentRecipeName);
            string nextRecipeDirectory = Path.Combine(selectorRoot, nextRecipeName);
            string manifestImageRoot = Path.Combine(currentRecipeDirectory, "images");
            string legacyConfigImageRoot = Path.Combine(nextRecipeDirectory, "images");
            Directory.CreateDirectory(currentRecipeDirectory);
            Directory.CreateDirectory(nextRecipeDirectory);
            Directory.CreateDirectory(manifestImageRoot);
            Directory.CreateDirectory(legacyConfigImageRoot);

            var manifest = new LabelingDatasetManifest
            {
                RecipeName = currentRecipeName,
                DatasetPurpose = LabelingDatasetPurpose.ObjectDetection.ToString(),
                OutputRootPath = Path.Combine(selectorRoot, "DATA", currentRecipeName),
                ImageRootPath = manifestImageRoot,
                Classes = new List<string> { "OK", "NG", "Defect" },
                ArtifactSummary = new LabelingDatasetManifestArtifactSummary
                {
                    ImageCount = 12,
                    PrimaryLabelCount = 5,
                    PrimaryLabelKind = "boxes"
                }
            };
            File.WriteAllText(
                Path.Combine(currentRecipeDirectory, LabelingDatasetManifestService.FileName),
                JsonConvert.SerializeObject(manifest, Formatting.Indented));
            var legacyConfig = new CData();
            legacyConfig.ConfigureOutputRoot(Path.Combine(selectorRoot, "DATA", nextRecipeName));
            legacyConfig.ProjectSettings.PythonModel.ImageRootPath = legacyConfigImageRoot;
            AssertTrue(
                SerializeHelper.ToXmlFile(Path.Combine(nextRecipeDirectory, "VISION.xml"), legacyConfig),
                "selector legacy recipe config was not written");

            var selectorViewModel = new WpfDatasetSelectionWindowViewModel();
            selectorViewModel.LoadDatasets(selectorRoot, currentRecipeName);
            AssertEqual(2, selectorViewModel.Datasets.Count);
            AssertEqual(currentRecipeName, selectorViewModel.SelectedDataset.RecipeName);
            AssertTrue(selectorViewModel.SelectedDataset.IsCurrent, "selector should preselect the current dataset");
            AssertEqual("\uAC1D\uCCB4 \uD0D0\uC9C0", selectorViewModel.SelectedDataset.PurposeText);
            AssertTrue(selectorViewModel.SelectedDataset.ClassesText.Contains("OK", StringComparison.Ordinal), "selector should show manifest classes");
            AssertEqual(manifestImageRoot, selectorViewModel.SelectedDataset.ImageRootPath);
            AssertTrue(selectorViewModel.SelectedDataset.StoragePathText.Contains("\uB77C\uBCA8", StringComparison.Ordinal), "selector item should label storage path separately from image root");
            AssertTrue(selectorViewModel.SelectedDataset.ImageRootPathText.Contains("\uC6D0\uBCF8 \uC774\uBBF8\uC9C0", StringComparison.Ordinal), "selector item should label source image folder separately from storage");
            AssertEqual(12, selectorViewModel.SelectedDataset.ImageCount);
            AssertEqual(5, selectorViewModel.SelectedDataset.LabelCount);
            AssertTrue(selectorViewModel.StatusText.Contains("2", StringComparison.Ordinal), "selector status should show how many datasets can be opened");
            AssertTrue(selectorViewModel.Datasets.Any(item => item.RecipeName == nextRecipeName && !item.HasManifest), "selector should still show recipe folders that need setup repair");
            AssertTrue(selectorViewModel.Datasets.Any(item => item.RecipeName == nextRecipeName && item.ImageRootPath == legacyConfigImageRoot), "selector should fall back to VISION.xml image root when an old manifest has no image path");

            bool openRequested = false;
            bool createNewRequested = false;
            bool refreshRequested = false;
            bool selectorCancelRequested = false;
            selectorViewModel.ConfigureCommands(
                () => openRequested = true,
                () => createNewRequested = true,
                () => refreshRequested = true,
                () => selectorCancelRequested = true);
            selectorViewModel.OpenCommand.Execute(null);
            selectorViewModel.CreateNewCommand.Execute(null);
            selectorViewModel.RefreshCommand.Execute(null);
            selectorViewModel.CancelCommand.Execute(null);
            AssertTrue(openRequested && createNewRequested && refreshRequested && selectorCancelRequested, "selector commands should be shell-injectable");
        }
        finally
        {
            if (Directory.Exists(selectorRoot))
            {
                Directory.Delete(selectorRoot, recursive: true);
            }
        }
    }

    private static void TestWpfDatasetSetupRequestCreatesRecipeManifest()
    {
        if (System.Windows.Application.Current == null)
        {
            _ = new System.Windows.Application
            {
                ShutdownMode = System.Windows.ShutdownMode.OnExplicitShutdown
            };
        }

        string recipeName = "codex_dataset_setup_" + Guid.NewGuid().ToString("N");
        string recipeDirectory = Path.Combine(AppContext.BaseDirectory, "RECIPE", recipeName);
        string outputRoot = Path.Combine(AppContext.BaseDirectory, "DATA", recipeName);
        string existingRecipeName = recipeName + "_existing";
        string existingRecipeDirectory = Path.Combine(AppContext.BaseDirectory, "RECIPE", existingRecipeName);
        string existingOutputRoot = Path.Combine(AppContext.BaseDirectory, "DATA", existingRecipeName);
        string duplicateRecipeName = recipeName + "_duplicate";
        string duplicateRecipeDirectory = Path.Combine(AppContext.BaseDirectory, "RECIPE", duplicateRecipeName);
        CData previousData = CGlobal.Inst.Data;
        string previousRecipeName = CGlobal.Inst.Recipe.Name;
        WpfLabelingShellWindow window = null;

        try
        {
            var existingData = new CData();
            existingData.ConfigureOutputRoot(existingOutputRoot);
            existingData.ClassNamedList.Add(new CClassItem { Text = "Existing", DrawColor = Color.Gray });
            existingData.SaveConfig(existingRecipeName);

            window = new WpfLabelingShellWindow();
            var learningPanel = (WpfLearningWorkflowPanel)window.FindName("LearningWorkflowPanelControl");
            AssertTrue(learningPanel != null, "learning workflow panel was not created");

            WpfLearningModeItem segmentationPurpose = learningPanel.ViewModel.DatasetPurposeModes.First(item => item.Mode == WpfLearningMode.Segmentation);
            learningPanel.ViewModel.SelectedDatasetPurposeMode = segmentationPurpose;
            learningPanel.DatasetPurposeList.SelectedItem = segmentationPurpose;
            PumpWpfDispatcher(TimeSpan.FromMilliseconds(80));
            AssertEqual(LabelingDatasetPurpose.Segmentation, learningPanel.ViewModel.GetSelectedDatasetPurpose());

            window.ProjectConfigViewModel.RecipeName = existingRecipeName;
            WpfDatasetSetupWizardViewModel conflictWizardViewModel = InvokePrivateResult<WpfDatasetSetupWizardViewModel>(window, "CreateDatasetSetupWizardViewModel", segmentationPurpose);
            AssertTrue(!string.Equals(existingRecipeName, conflictWizardViewModel.RecipeName, StringComparison.OrdinalIgnoreCase), "new dataset wizard should not default to an existing recipe name");
            AssertTrue(
                !string.Equals(
                    Path.GetFullPath(existingOutputRoot),
                    Path.GetFullPath(conflictWizardViewModel.OutputRootPath),
                    StringComparison.OrdinalIgnoreCase),
                "new dataset wizard should not default to an output root already used by an existing recipe");

            var duplicateRequest = new WpfDatasetSetupRequest
            {
                Purpose = LabelingDatasetPurpose.ObjectDetection,
                RecipeName = duplicateRecipeName,
                OutputRootPath = existingOutputRoot,
                ClassNames = new[] { "Part" }
            };
            AssertTrue(!InvokePrivateResult<bool>(window, "ApplyDatasetSetupRequest", duplicateRequest), "dataset setup should reject an output root already used by another recipe");
            AssertTrue(!Directory.Exists(duplicateRecipeDirectory), "rejected duplicate output-root request should not create a recipe directory");

            window.ProjectConfigViewModel.RecipeName = recipeName;
            WpfDatasetSetupWizardViewModel wizardViewModel = InvokePrivateResult<WpfDatasetSetupWizardViewModel>(window, "CreateDatasetSetupWizardViewModel", segmentationPurpose);
            AssertEqual(LabelingDatasetPurpose.Segmentation, WpfLearningWorkflowPanelViewModel.ToDatasetPurpose(wizardViewModel.SelectedDatasetPurposeMode.Mode));
            wizardViewModel.RecipeName = recipeName;
            wizardViewModel.OutputRootPath = outputRoot;
            wizardViewModel.ClassNamesText = "Defect\r\nScratch";
            AssertTrue(wizardViewModel.TryBuildRequest(out WpfDatasetSetupRequest request, out string error), error);
            AssertTrue(InvokePrivateResult<bool>(window, "ApplyDatasetSetupRequest", request), "dataset setup request should be applied");
            PumpWpfDispatcher(TimeSpan.FromMilliseconds(250));

            string manifestPath = Path.Combine(recipeDirectory, LabelingDatasetManifestService.FileName);
            AssertTrue(File.Exists(Path.Combine(recipeDirectory, "VISION.xml")), "dataset setup should create VISION.xml");
            AssertTrue(File.Exists(manifestPath), "dataset setup should create dataset.manifest.json");
            AssertTrue(Directory.Exists(Path.Combine(outputRoot, "data", "train", "images")), "dataset setup should create train image folder");
            AssertTrue(File.Exists(Path.Combine(outputRoot, "data.yaml")), "dataset setup should create data.yaml");
            AssertEqual(LabelingDatasetPurpose.Segmentation, CGlobal.Inst.Data.ProjectSettings.DatasetPurpose);
            AssertTrue(learningPanel.ViewModel.DatasetSetupStatusText.Contains(recipeName, StringComparison.Ordinal), "dataset setup status should name the prepared recipe");

            LabelingDatasetManifest manifest = JsonConvert.DeserializeObject<LabelingDatasetManifest>(File.ReadAllText(manifestPath));
            AssertTrue(manifest != null, "dataset setup manifest should deserialize");
            AssertEqual(recipeName, manifest.RecipeName);
            AssertEqual(LabelingDatasetPurpose.Segmentation.ToString(), manifest.DatasetPurpose);
            AssertEqual("mask-and-polygon", manifest.AnnotationProfile);
            AssertTrue(!string.IsNullOrWhiteSpace(manifest.ImageRootPath), "dataset setup manifest should include the active image folder path");
            AssertTrue(manifest.Classes.Contains("Scratch"), "dataset setup manifest should include wizard initial classes");
            AssertEqual(2, manifest.SchemaVersion);
            AssertTrue(!string.IsNullOrWhiteSpace(manifest.DatasetVersionId), "dataset setup manifest should include a dataset version id");
            AssertEqual("masks", manifest.ArtifactSummary.PrimaryLabelKind);
            AssertEqual(0, manifest.ArtifactSummary.PrimaryLabelCount);
        }
        finally
        {
            window?.Close();
            if (!string.Equals(CGlobal.Inst.Recipe.Name, previousRecipeName, StringComparison.Ordinal))
            {
                CGlobal.Inst.Recipe.Name = previousRecipeName;
            }

            CGlobal.Inst.Data = previousData;

            if (Directory.Exists(recipeDirectory))
            {
                Directory.Delete(recipeDirectory, recursive: true);
            }

            if (Directory.Exists(outputRoot))
            {
                Directory.Delete(outputRoot, recursive: true);
            }

            if (Directory.Exists(existingRecipeDirectory))
            {
                Directory.Delete(existingRecipeDirectory, recursive: true);
            }

            if (Directory.Exists(existingOutputRoot))
            {
                Directory.Delete(existingOutputRoot, recursive: true);
            }

            if (Directory.Exists(duplicateRecipeDirectory))
            {
                Directory.Delete(duplicateRecipeDirectory, recursive: true);
            }
        }
    }

    private static void TestWpfAnnotationWorkflowService()
    {
        AssertEqual(WpfLearningModeWorkflowAction.Labeling, WpfAnnotationWorkflowService.ResolveModeAction(WpfLearningMode.ObjectDetection));
        AssertEqual(WpfLearningModeWorkflowAction.Inference, WpfAnnotationWorkflowService.ResolveModeAction(WpfLearningMode.Infer));
        AssertEqual(WpfLearningModeWorkflowAction.Inference, WpfAnnotationWorkflowService.ResolveModeAction(WpfLearningMode.Review));
        AssertEqual(WpfLearningModeWorkflowAction.LabelingAndFocusYoloSettings, WpfAnnotationWorkflowService.ResolveModeAction(WpfLearningMode.Train));
        AssertEqual(WpfLearningModeWorkflowAction.Labeling, WpfAnnotationWorkflowService.ResolveModeAction(WpfLearningMode.Segmentation));

        AssertEqual(WpfLearningStepWorkflowAction.LoadSample, WpfAnnotationWorkflowService.ResolveStepAction(WpfLearningStep.Sample));
        AssertEqual(WpfLearningStepWorkflowAction.StartBoxLabeling, WpfAnnotationWorkflowService.ResolveStepAction(WpfLearningStep.Label));
        AssertEqual(WpfLearningStepWorkflowAction.Inference, WpfAnnotationWorkflowService.ResolveStepAction(WpfLearningStep.Infer));
        AssertEqual(WpfLearningStepWorkflowAction.ShowCandidateReview, WpfAnnotationWorkflowService.ResolveStepAction(WpfLearningStep.Review));
        AssertEqual(WpfLearningStepWorkflowAction.SaveAnnotations, WpfAnnotationWorkflowService.ResolveStepAction(WpfLearningStep.Save));

        WpfAnnotationToolWorkflowAction rectangle = WpfAnnotationWorkflowService.ResolveToolAction(WpfAnnotationTool.Rectangle);
        AssertEqual(WpfAnnotationToolWorkflowActionKind.DrawRoi, rectangle.Kind);
        AssertEqual(CanvasRoiShapeKind.Rectangle, rectangle.ShapeKind);
        AssertTrue(rectangle.Capability.IsConnected, "rectangle action should use a connected WPF ROI path");
        AssertTrue(rectangle.CommandStatusText.Contains("\uB4DC\uB798\uADF8", StringComparison.Ordinal), "rectangle action should explain the drag-to-label UX");

        WpfAnnotationToolWorkflowAction ellipse = WpfAnnotationWorkflowService.ResolveToolAction(WpfAnnotationTool.Ellipse);
        AssertEqual(WpfAnnotationToolWorkflowActionKind.DrawRoi, ellipse.Kind);
        AssertEqual(CanvasRoiShapeKind.Ellipse, ellipse.ShapeKind);

        AssertEqual(WpfAnnotationToolWorkflowActionKind.Select, WpfAnnotationWorkflowService.ResolveToolAction(WpfAnnotationTool.Select).Kind);
        AssertEqual(WpfAnnotationToolWorkflowActionKind.Polygon, WpfAnnotationWorkflowService.ResolveToolAction(WpfAnnotationTool.Polygon).Kind);
        AssertEqual(WpfAnnotationToolWorkflowActionKind.Brush, WpfAnnotationWorkflowService.ResolveToolAction(WpfAnnotationTool.Brush).Kind);
        AssertEqual(WpfAnnotationToolWorkflowActionKind.Eraser, WpfAnnotationWorkflowService.ResolveToolAction(WpfAnnotationTool.Eraser).Kind);
        AssertEqual(WpfAnnotationToolWorkflowActionKind.PanZoom, WpfAnnotationWorkflowService.ResolveToolAction(WpfAnnotationTool.PanZoom).Kind);
        AssertEqual(WpfAnnotationToolWorkflowActionKind.Delete, WpfAnnotationWorkflowService.ResolveToolAction(WpfAnnotationTool.Delete).Kind);
        AssertEqual(WpfAnnotationToolWorkflowActionKind.Undo, WpfAnnotationWorkflowService.ResolveToolAction(WpfAnnotationTool.Undo).Kind);
        AssertEqual(WpfAnnotationToolWorkflowActionKind.Redo, WpfAnnotationWorkflowService.ResolveToolAction(WpfAnnotationTool.Redo).Kind);

        WpfAnnotationToolWorkflowAction pending = WpfAnnotationWorkflowService.ResolveToolAction((WpfAnnotationTool)999);
        AssertEqual(WpfAnnotationToolWorkflowActionKind.Pending, pending.Kind);
        AssertTrue(!pending.Capability.IsConnected, "unknown tools should remain pending until a verified WPF path is registered");
        AssertTrue(pending.Capability.StatusText.Contains("\uC544\uC9C1 \uC0AC\uC6A9\uD560 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4", StringComparison.Ordinal), "pending tools should explain that the tool is not available yet");
    }

    private static void TestWpfAnnotationToolVerificationMatrix()
    {
        string root = FindRepositoryRoot();
        string validationPath = Path.Combine(root, "docs", "WPF_ANNOTATION_TOOL_VALIDATION.md");
        string objectVerificationPath = Path.Combine(root, "docs", "WPF_ANNOTATION_OBJECT_VERIFICATION.md");
        string legacyAnnotationScriptPath = Path.Combine(root, "scripts", "verify-wpf-annotation-objects.ps1");
        string focusedAnnotationScriptPath = Path.Combine(root, "scripts", "verify-wpf-annotation-object-interactions.ps1");
        string focusedRoiScriptPath = Path.Combine(root, "scripts", "verify-wpf-roi-object-interactions.ps1");
        string focusedSegmentationScriptPath = Path.Combine(root, "scripts", "verify-wpf-segmentation-object-interactions.ps1");
        string firstRunScriptPath = Path.Combine(root, "scripts", "verify-first-run.ps1");
        string canvasModeSource = File.ReadAllText(Path.Combine(root, "OpenVisionLab", "Library", "OpenVisionLab.ImageCanvas", "Canvas", "CanvasInteractionMode.cs"));
        string roiViewModelSource = File.ReadAllText(Path.Combine(root, "OpenVisionLab", "Library", "OpenVisionLab.ImageCanvas", "ViewModel", "RoiImageCanvasViewModel.cs"));
        string maskOverlaySource = File.ReadAllText(Path.Combine(root, "OpenVisionLab", "Library", "OpenVisionLab.ImageCanvas", "ViewModel", "RoiImageCanvasMaskOverlay.cs"));
        string roiMouseUpSource = File.ReadAllText(Path.Combine(root, "OpenVisionLab", "Library", "OpenVisionLab.ImageCanvas", "RoiInteraction", "RoiInteractionMouseUp.cs"));
        string imageCanvasSource = File.ReadAllText(Path.Combine(root, "OpenVisionLab", "Library", "OpenVisionLab.ImageCanvas", "Engine", "ImageCanvasControl.cs"));
        string shapeDrawingSource = File.ReadAllText(Path.Combine(root, "OpenVisionLab", "Library", "OpenVisionLab.ImageCanvas", "OpenGL", "OpenGlShapeDrawing.cs"));
        string overlayCompilerSource = File.ReadAllText(Path.Combine(root, "OpenVisionLab", "Library", "OpenVisionLab.ImageCanvas", "OpenGL", "OpenGlOverlayCompiler.cs"));
        string overlayExtensionsSource = File.ReadAllText(Path.Combine(root, "OpenVisionLab", "Library", "OpenVisionLab.ImageCanvas", "OpenGL", "OpenGlOverlayExtensions.cs"));
        string cViewerSource = File.ReadAllText(Path.Combine(root, "Library", "CViewer.cs"));
        string shellSource = ReadWpfLabelingShellWindowSources();

        AssertTrue(File.Exists(validationPath), "WPF annotation tool validation matrix should be documented");
        AssertTrue(File.Exists(objectVerificationPath), "WPF annotation object verification gate should be documented");
        AssertTrue(File.Exists(legacyAnnotationScriptPath), "legacy annotation verification script name should remain available");
        AssertTrue(File.Exists(focusedAnnotationScriptPath), "focused annotation object verification script should exist");
        AssertTrue(File.Exists(focusedRoiScriptPath), "focused ROI object verification script should exist");
        AssertTrue(File.Exists(focusedSegmentationScriptPath), "focused segmentation object verification script should exist");
        string validation = File.ReadAllText(validationPath);
        string objectVerification = File.ReadAllText(objectVerificationPath);
        string legacyAnnotationScript = File.ReadAllText(legacyAnnotationScriptPath);
        string focusedAnnotationScript = File.ReadAllText(focusedAnnotationScriptPath);
        string focusedRoiScript = File.ReadAllText(focusedRoiScriptPath);
        string focusedSegmentationScript = File.ReadAllText(focusedSegmentationScriptPath);
        string firstRunScript = File.ReadAllText(firstRunScriptPath);
        AssertTrue(validation.Contains("Validation Criteria", StringComparison.Ordinal), "validation document should state the verification criteria");
        AssertTrue(validation.Contains("Ellipse/Circle", StringComparison.Ordinal), "validation document should include ellipse/circle");
        AssertTrue(validation.Contains("Polygon", StringComparison.Ordinal), "validation document should include polygon");
        AssertTrue(validation.Contains("Brush", StringComparison.Ordinal), "validation document should include brush");
        AssertTrue(validation.Contains("Undo", StringComparison.Ordinal), "validation document should include undo");
        AssertTrue(validation.Contains("WpfAnnotationHistoryService", StringComparison.Ordinal), "validation document should include the WPF annotation history path");
        AssertTrue(validation.Contains("All palette tools currently have a verified first WPF path", StringComparison.Ordinal), "validation document should state that the current palette has no pending first-path tools");
        AssertTrue(objectVerification.Contains("--wpf-annotation-object-verification", StringComparison.Ordinal), "object verification document should name the combined annotation gate");
        AssertTrue(objectVerification.Contains("scripts\\verify-wpf-annotation-object-interactions.ps1", StringComparison.Ordinal), "object verification document should name the focused annotation script");
        AssertTrue(legacyAnnotationScript.Contains("--wpf-annotation-object-verification", StringComparison.Ordinal), "legacy annotation verification script should run the combined gate");
        AssertTrue(legacyAnnotationScript.Contains("--no-build", StringComparison.Ordinal), "legacy annotation verification script should build once and reuse the output for focused tests");
        AssertTrue(focusedAnnotationScript.Contains("--wpf-annotation-object-verification", StringComparison.Ordinal), "focused annotation script should run the combined gate");
        AssertTrue(focusedRoiScript.Contains("--wpf-roi-object-verification", StringComparison.Ordinal), "focused ROI script should run the ROI gate");
        AssertTrue(focusedSegmentationScript.Contains("--wpf-segmentation-object-verification", StringComparison.Ordinal), "focused segmentation script should run the segmentation gate");
        AssertTrue(firstRunScript.Contains("verify-wpf-annotation-object-interactions.ps1", StringComparison.Ordinal), "first-run script syntax check should include the focused annotation object script");
        AssertTrue(shellSource.Contains("UndoWpfAnnotationHistory", StringComparison.Ordinal), "WPF shell should expose its own undo history command");
        AssertTrue(shellSource.Contains("RedoWpfAnnotationHistory", StringComparison.Ordinal), "WPF shell should expose its own redo history command");
        AssertTrue(validation.Contains("The source of truth must be the original image coordinate system", StringComparison.Ordinal), "validation document should define image-pixel annotations as the implementation direction");
        AssertTrue(validation.Contains("Do not route a WPF palette action through legacy `CViewer`", StringComparison.Ordinal), "validation document should keep WPF actions off legacy CViewer shortcuts");

        AssertTrue(canvasModeSource.Contains("Drawing", StringComparison.Ordinal), "WPF canvas should expose the existing rectangle drawing mode");
        AssertTrue(canvasModeSource.Contains("Drag", StringComparison.Ordinal), "WPF canvas should expose the existing pan mode");
        AssertTrue(!canvasModeSource.Contains("Brush", StringComparison.Ordinal), "WPF canvas mode should keep brush input as image-point input instead of a legacy viewer mode");
        AssertTrue(!canvasModeSource.Contains("Polygon", StringComparison.Ordinal), "WPF canvas mode should not pretend polygon input is verified");
        AssertTrue(!canvasModeSource.Contains("Ellipse", StringComparison.Ordinal), "WPF canvas mode should keep shape type separate from viewer mode");

        AssertTrue(roiMouseUpSource.Contains("AddRectangleToOverlay", StringComparison.Ordinal), "WPF ROI interaction should have a concrete rectangle add path");
        AssertTrue(roiMouseUpSource.Contains("AddEllipseToOverlay", StringComparison.Ordinal), "WPF ROI interaction should have a concrete ellipse add path");
        AssertTrue(roiMouseUpSource.Contains("CanvasRoiShapeKind.Ellipse", StringComparison.Ordinal), "ellipse drawing should use the pixel-space ROI shape kind");
