        string direction = File.ReadAllText(directionPath, Encoding.UTF8);
        string yoloWorkflow = File.ReadAllText(yoloWorkflowPath, Encoding.UTF8);
        string segmentationWorkflow = File.ReadAllText(segmentationWorkflowPath, Encoding.UTF8);
        string anomalyWorkflow = File.ReadAllText(anomalyWorkflowPath, Encoding.UTF8);
        string tutorialReadme = File.ReadAllText(tutorialReadmePath, Encoding.UTF8);
        string tutorialHtml = File.ReadAllText(tutorialHtmlPath, Encoding.UTF8);
        string tutorialStandaloneHtml = File.ReadAllText(tutorialStandaloneHtmlPath, Encoding.UTF8);

        AssertTrue(readme.Contains("YOLOV5_TRAINING_RESULT_WORKFLOW.md", StringComparison.Ordinal), "README should link the YOLOv5 workflow criteria");
        AssertTrue(readme.Contains("SEGMENTATION_UX_COMPLETION.md", StringComparison.Ordinal), "README should link the segmentation UX criteria");
        AssertTrue(readme.Contains("ANOMALY_DETECTION_FLOW.md", StringComparison.Ordinal), "README should link the anomaly detection criteria");
        AssertTrue(codeStructure.Contains("OpenVisionLab Labeling Studio", StringComparison.Ordinal), "code structure should use the public product name");
        AssertTrue(!codeStructure.Contains("`Labelling_Application`", StringComparison.Ordinal), "code structure should not present the repository folder name as the product identity");
        AssertTrue(codeStructure.Contains("docs/YOLOV5_TRAINING_RESULT_WORKFLOW.md", StringComparison.Ordinal), "code structure should route priority 3 to the YOLOv5 workflow criteria");
        AssertTrue(codeStructure.Contains("docs/SEGMENTATION_UX_COMPLETION.md", StringComparison.Ordinal), "code structure should route priority 4 to the segmentation UX criteria");
        AssertTrue(codeStructure.Contains("docs/ANOMALY_DETECTION_FLOW.md", StringComparison.Ordinal), "code structure should route priority 5 to the anomaly detection criteria");
        AssertTrue(direction.Contains("178. YOLOv5 training/result-comparison", StringComparison.Ordinal), "program direction should record the YOLOv5 workflow criteria");
        AssertTrue(direction.Contains("179. Segmentation UX completion", StringComparison.Ordinal), "program direction should record the segmentation UX criteria");
        AssertTrue(direction.Contains("180. Anomaly detection flow", StringComparison.Ordinal), "program direction should record the anomaly flow criteria");

        AssertTrue(yoloWorkflow.Contains("--wpf-yolo-training-session-smoke", StringComparison.Ordinal), "YOLOv5 workflow criteria should keep the WPF training session gate");
        AssertTrue(yoloWorkflow.Contains("--real-yolo-smoke", StringComparison.Ordinal), "YOLOv5 workflow criteria should keep the real YOLO smoke gate");
        AssertTrue(yoloWorkflow.Contains("compare-yolo-models.ps1", StringComparison.Ordinal), "YOLOv5 workflow criteria should keep the model comparison script");
        AssertTrue(yoloWorkflow.Contains("-Task test", StringComparison.Ordinal), "YOLOv5 workflow criteria should require test split comparison before model replacement");
        AssertTrue(segmentationWorkflow.Contains("--wpf-segmentation-object-verification", StringComparison.Ordinal), "segmentation criteria should keep the segmentation object gate");
        AssertTrue(segmentationWorkflow.Contains("--wpf-mask-drag-performance", StringComparison.Ordinal), "segmentation criteria should keep the mask drag performance gate");
        AssertTrue(segmentationWorkflow.Contains("--exe-mask-tools-smoke", StringComparison.Ordinal), "segmentation criteria should keep the real-EXE mask smoke");
        AssertTrue(segmentationWorkflow.Contains("MouseMove", StringComparison.Ordinal), "segmentation criteria should protect the high-frequency input path");
        AssertTrue(anomalyWorkflow.Contains("image-level normal/abnormal", StringComparison.Ordinal), "anomaly criteria should start with image-level normal/abnormal labels");
        AssertTrue(anomalyWorkflow.Contains("--wpf-anomaly-purpose-flow", StringComparison.Ordinal), "anomaly criteria should define the first WPF purpose-flow gate");
        AssertTrue(anomalyWorkflow.Contains("gate가 생기기 전에는 anomaly 기능을 `완료`로 표시하지 않습니다.", StringComparison.Ordinal), "anomaly criteria should prohibit claiming completion before gates exist");

        var publicDocuments = new Dictionary<string, string>
        {
            ["README.md"] = readme,
            ["docs/tutorial/README.md"] = tutorialReadme,
            ["docs/tutorial/labeling-workbench-tutorial.html"] = tutorialHtml,
            ["docs/tutorial/labeling-workbench-tutorial-standalone.html"] = tutorialStandaloneHtml
        };

        string[] privateOrDraftMarkers =
        {
            "C:\\",
            "C:/",
            "D:\\",
            "D:/",
            "LabelingData",
            "Test01",
            "TEST2",
            "TEST_",
            "Debug\\DATA",
            "artifacts\\run",
            "AppData",
            "Temp\\codex",
            "Codex",
            "\uD3EC\uD2B8\uD3F4\uB9AC\uC624",
            "제가",
            "\uB0B4\uAC00",
            "\uC800\uB9CC",
            "당신",
            "소통",
            "이번 확인",
            "사용한 데이터",
            "AI가 작성"
        };

        foreach (KeyValuePair<string, string> document in publicDocuments)
        {
            foreach (string marker in privateOrDraftMarkers)
            {
                AssertTrue(
                    !document.Value.Contains(marker, StringComparison.OrdinalIgnoreCase),
                    $"public documentation should not contain private path or conversation marker '{marker}' in {document.Key}");
            }
        }

        int linkedTutorialImageCount = tutorialHtml.Split(new[] { "src=\"images/" }, StringSplitOptions.None).Length - 1;
        int embeddedTutorialImageCount = tutorialStandaloneHtml.Split(new[] { "src=\"data:image" }, StringSplitOptions.None).Length - 1;
        int annotatedAltTextCount = tutorialHtml.Split(new[] { "alt=\"번호와 화살표" }, StringSplitOptions.None).Length - 1;

        AssertTrue(linkedTutorialImageCount >= 10, "tutorial HTML should keep the full annotated screenshot walkthrough");
        AssertEqual(linkedTutorialImageCount, embeddedTutorialImageCount);
        AssertEqual(linkedTutorialImageCount, annotatedAltTextCount);
        AssertTrue(!tutorialStandaloneHtml.Contains("src=\"images/", StringComparison.Ordinal), "standalone tutorial should embed screenshots instead of referencing local image files");

        foreach (string imageSource in ExtractHtmlImageSources(tutorialHtml))
        {
            AssertTrue(
                imageSource.StartsWith("images/annotated/", StringComparison.Ordinal),
                $"tutorial HTML should use annotated screenshots only: {imageSource}");
            AssertTrue(
                imageSource.EndsWith("-annotated.png", StringComparison.Ordinal),
                $"tutorial screenshot should use the annotated export, not a raw capture: {imageSource}");
            AssertTrue(
                imageSource.Contains("-1920-", StringComparison.Ordinal) || imageSource.Contains("-actual-", StringComparison.Ordinal),
                $"tutorial screenshot should use current large EXE captures: {imageSource}");

            string imagePath = Path.Combine(root, "docs", "tutorial", imageSource.Replace('/', Path.DirectorySeparatorChar));
            AssertTrue(File.Exists(imagePath), $"tutorial screenshot file should exist: {imageSource}");
        }
    }

    private static IReadOnlyList<string> ExtractHtmlImageSources(string html)
    {
        var sources = new List<string>();
        string[] imageTags = html.Split(new[] { "<img" }, StringSplitOptions.None);

        for (int i = 1; i < imageTags.Length; i++)
        {
            int sourceStart = imageTags[i].IndexOf("src=\"", StringComparison.Ordinal);
            if (sourceStart < 0)
            {
                continue;
            }

            sourceStart += "src=\"".Length;
            int sourceEnd = imageTags[i].IndexOf('"', sourceStart);
            if (sourceEnd <= sourceStart)
            {
                continue;
            }

            sources.Add(imageTags[i].Substring(sourceStart, sourceEnd - sourceStart));
        }

        return sources;
    }

    private static void TestWpfEllipseAnnotationStoresPixelBounds()
    {
        if (System.Windows.Application.Current == null)
        {
            _ = new System.Windows.Application
            {
                ShutdownMode = System.Windows.ShutdownMode.OnExplicitShutdown
            };
        }

        CData previousData = CGlobal.Inst.Data;
        string root = CreateTempRoot();

        try
        {
            var data = new CData();
            data.ConfigureOutputRoot(root);
            data.LastSelectImageName = "ellipse-sample";
            data.ClassNamedList.Add(new CClassItem { Text = "Defect", DrawColor = Color.Lime });
            CGlobal.Inst.Data = data;

            WpfLabelingShellWindow window = new WpfLabelingShellWindow();
            try
            {
                SetPrivateField(window, "activeImageSize", new Size(100, 100));
                SetPrivateField(window, "activeImageBitmap", new Bitmap(100, 100));

                var rect = new CanvasRect<float>(10, 80, 50, 40)
                {
                    UniqueId = "ellipse-1",
                    ShapeKind = CanvasRoiShapeKind.Ellipse
                };
                var args = new RoiChangedEventArgs { RoiRect = rect };

                InvokePrivateResult<object>(window, "MainCanvasViewModel_RoiAdded", window.MainCanvasViewModel, args);

                var manualRois = GetPrivateField<List<Rectangle>>(window, "manualRois");
                var manualShapeKinds = GetPrivateField<List<CanvasRoiShapeKind>>(window, "manualRoiShapeKinds");
                var manualOverlayIds = GetPrivateField<List<string>>(window, "manualRoiOverlayIds");
                AssertEqual(1, manualRois.Count);
                AssertEqual(new Rectangle(10, 20, 40, 40), manualRois[0]);
                AssertEqual(CanvasRoiShapeKind.Ellipse, manualShapeKinds[0]);
                AssertEqual("ellipse-1", manualOverlayIds[0]);

                Dictionary<string, List<CRectangleObject>> roisByClass = InvokePrivateResult<Dictionary<string, List<CRectangleObject>>>(window, "BuildAnnotationRois");
                AssertTrue(roisByClass.ContainsKey("Defect"), "ellipse annotation should export through the selected/default class");
                AssertEqual(new Rectangle(10, 20, 40, 40), roisByClass["Defect"][0].Roi);

                InvokePrivate(window, "RedrawReviewRois");
                AssertEqual(CanvasRoiShapeKind.Ellipse, manualShapeKinds[0]);
                AssertTrue(!string.IsNullOrWhiteSpace(manualOverlayIds[0]), "redraw should keep a live overlay id for later edit/delete sync");
            }
            finally
            {
                window.Close();
            }
        }
        finally
        {
            CGlobal.Inst.Data = previousData;
            DeleteTempRoot(root);
        }
    }

    private static void TestWpfTutorialSampleFlowSideEffects()
    {
        if (System.Windows.Application.Current == null)
        {
            _ = new System.Windows.Application
            {
                ShutdownMode = System.Windows.ShutdownMode.OnExplicitShutdown
            };
        }

        CData previousData = CGlobal.Inst.Data;
        string root = CreateTempRoot();

        try
        {
            string sampleRoot = Path.Combine(root, "images");
            string outputRoot = Path.Combine(root, "dataset");
            Directory.CreateDirectory(sampleRoot);
            string imagePath = Path.Combine(sampleRoot, "tutorial-sample.jpg");
            CreateVisualSmokeImage(imagePath);

            var data = new CData();
            data.ConfigureOutputRoot(outputRoot);
            data.ProjectSettings.PythonModel.ImageRootPath = sampleRoot;
            data.ProjectSettings.PythonModel.ProjectRootPath = root;
            data.ProjectSettings.YoloDataset.ValidationPercent = 0;
            data.ClassNamedList.Add(new CClassItem { Text = "Defect", DrawColor = Color.Lime });
            CGlobal.Inst.Data = data;

            WpfLabelingShellWindow window = new WpfLabelingShellWindow();
            try
            {
                var learningPanel = (WpfLearningWorkflowPanel)window.FindName("LearningWorkflowPanelControl");
                var detectButton = (System.Windows.Controls.Control)window.FindName("DetectButton");
                var objectsTab = (System.Windows.Controls.TabItem)window.FindName("ObjectsReviewTab");
                var candidatesTab = (System.Windows.Controls.TabItem)window.FindName("CandidatesReviewTab");

                SelectTutorialStep(window, learningPanel, WpfLearningStep.Sample);
                AssertEqual(imagePath, GetPrivateField<string>(window, "activeImagePath"));
                AssertTrue(window.ImageQueueItems.Count > 0, "tutorial sample step should populate the image queue");

                SelectTutorialStep(window, learningPanel, WpfLearningStep.Label);
                var manualRois = GetPrivateField<List<System.Drawing.Rectangle>>(window, "manualRois");
                AssertEqual(1, manualRois.Count);
                AssertEqual(WpfAnnotationTool.Rectangle, learningPanel.ViewModel.SelectedTool.Tool);
                AssertTrue(objectsTab.IsSelected, "tutorial label step should move the user to object review");
                AssertTrue(!detectButton.IsEnabled, "tutorial label step should keep inference disabled in labeling mode");

                SelectTutorialStep(window, learningPanel, WpfLearningStep.Infer);
                AssertTrue(detectButton.IsEnabled, "tutorial infer step should enable current-image inference");

                objectsTab.IsSelected = true;
                SelectTutorialStep(window, learningPanel, WpfLearningStep.Review);
                AssertTrue(candidatesTab.IsSelected, "tutorial review step should select the AI candidate review tab");

                SelectTutorialStep(window, learningPanel, WpfLearningStep.Save);
                string labelPath = Path.Combine(outputRoot, "data", "train", "labels", "tutorial-sample.txt");
                AssertTrue(File.Exists(labelPath), "tutorial save step should write the YOLO label file");
                AssertTrue(File.ReadAllLines(labelPath).Length > 0, "tutorial save step should persist at least one label line");
            }
            finally
            {
                window.Close();
            }
        }
        finally
        {
            CGlobal.Inst.Data = previousData;
            DeleteTempRoot(root);
        }
    }

