    private static void TestWpfImageQueueSelectionService()
    {
        string root = CreateTempRoot();
        try
        {
            string firstPath = Path.Combine(root, "a.jpg");
            string secondPath = Path.Combine(root, "b.PNG");
            string ignoredPath = Path.Combine(root, "ignore.txt");
            File.WriteAllText(firstPath, string.Empty);
            File.WriteAllText(secondPath, string.Empty);
            File.WriteAllText(ignoredPath, string.Empty);

            var service = new WpfImageQueueSelectionService();
            List<string> paths = service.EnumerateImageFiles(root);
            AssertEqual(2, paths.Count);
            AssertEqual(firstPath, paths[0]);
            AssertEqual(secondPath, paths[1]);
            AssertTrue(service.HasSupportedExtension(firstPath), "image queue selection service should accept supported image extensions");
            AssertTrue(!service.HasSupportedExtension(ignoredPath), "image queue selection service should reject unsupported files");

            IReadOnlyList<WpfImageQueueItem> items = service.CreateShellItems(paths);
            WpfImageQueueItem firstItem = service.FindItem(items, firstPath);
            WpfImageQueueItem secondItem = service.FindItem(items, secondPath);
            AssertTrue(firstItem != null, "image queue selection service should find the first item by path");
            AssertTrue(secondItem != null, "image queue selection service should find the second item by path");
            AssertTrue(service.CanOpen(firstItem), "image queue selection service should enable existing image rows");
            AssertTrue(ReferenceEquals(secondItem, service.ResolveSelectedItem(null, items, secondPath)), "transient null queue selections should preserve the active image row");
            AssertTrue(service.ShouldOpen(secondItem, firstPath, skipIfAlreadyActive: true), "queue selection should open a different image");
            AssertTrue(!service.ShouldOpen(secondItem, secondPath, skipIfAlreadyActive: true), "queue selection should skip reloading the already active image");
            AssertTrue(service.IsSameRoot(root, Path.GetFullPath(root)), "image queue selection service should compare canonical roots");

            string missingStagingPath = Path.Combine(root, "staging", "saved-part.bmp");
            WpfImageQueueItem savedSplitItem = WpfImageQueueItem.CreateShell(missingStagingPath);
            string savedSplitImagePath = Path.Combine(root, "data", "valid", "images", "saved-part.jpg");
            Directory.CreateDirectory(Path.GetDirectoryName(savedSplitImagePath));
            File.WriteAllText(savedSplitImagePath, string.Empty);
            var data = new CData();
            data.ConfigureOutputRoot(root);
            AssertTrue(service.TryResolveOpenImagePath(savedSplitItem, data, out string resolvedSplitImagePath), "queue open should recover saved split image copies when the staging source path no longer exists");
            AssertEqual(savedSplitImagePath, resolvedSplitImagePath);
            WpfImageQueueItem missingCandidate = WpfImageQueueItem.CreateShell(Path.Combine(root, "missing", "not-openable.jpg"));
            WpfImageQueueOpenSelection openSelection = service.ResolveOpenSelection(new[] { missingCandidate, savedSplitItem }, data);
            AssertTrue(openSelection.CanOpen, "open selection should resolve the first openable candidate");
            AssertTrue(ReferenceEquals(savedSplitItem, openSelection.Item), "open selection should preserve the queue item tied to the resolved split image");
            AssertEqual(savedSplitImagePath, openSelection.OpenImagePath);

            var resolver = new WpfDatasetImageRootResolver();
            string explicitImageRoot = Path.Combine(root, "operator-images");
            Directory.CreateDirectory(explicitImageRoot);
            File.WriteAllText(Path.Combine(explicitImageRoot, "operator-a.jpg"), string.Empty);
            string datasetOutputRoot = Path.Combine(root, "dataset-output");
            var datasetData = new CData();
            datasetData.ConfigureOutputRoot(datasetOutputRoot);
            datasetData.EnsureYoloOutputDirectories();
            File.WriteAllText(Path.Combine(datasetData.TrainImagesPath, "copied-a.jpg"), string.Empty);

            string resolvedExplicitRoot = resolver.Resolve(datasetData, explicitImageRoot, path => service.EnumerateImageFiles(path).Count > 0);
            AssertEqual(explicitImageRoot, resolvedExplicitRoot);

            string resolvedDatasetRoot = resolver.Resolve(datasetData, Path.Combine(root, "missing-image-root"), path => service.EnumerateImageFiles(path).Count > 0);
            AssertEqual(datasetData.TrainImagesPath, resolvedDatasetRoot);
        }
        finally
        {
            DeleteTempRoot(root);
        }
    }
